var CONTENT_EN = {

  /* ===== 坤宫 ===== */
  0: { /* 坤为地 KW#2, 坤上坤下 */
    name: "Kūn — The Receptive (Earth)",
    guaciExplain: "Supreme success through perseverance, like a mare. The noble person sets out, first losing direction then finding a guide. In the southwest, gain allies; in the northeast, lose allies. Peaceful perseverance brings good fortune.",
    xiangExplain: "The earth's condition is receptive devotion. The noble person with profound virtue supports all beings. [地势坤 Dì Shì Kūn — Earth's way: supportive, nurturing, all-embracing.]",
    modern: { career: "Success through steady cooperation, not aggressive solo pursuits. Like earth supporting all life, focus on helping others and building strong foundations. Be patient; avoid reckless risks.", wealth: "Financial opportunities not yet ripe. Store resources patiently. Steady accumulation brings lasting prosperity.", love: "Yin energy dominates: the feminine principle of receptivity creates harmony. Gentle patience in love wins more than forceful pursuit.", health: "Focus on digestive and muscular health. Chronic conditions need gentle, consistent care — like earth slowly building mountains.", interpersonal: "Your sincere, generous nature attracts supporters. Maintain healthy boundaries — kindness needs wisdom to avoid exploitation." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Treading on frost — solid ice soon follows. Recognize subtle signs before they manifest fully. When yin energy coalesces, observe nature's progression and prepare." },
      1: { explain: "Six in the second (六二): Straight, square, great — without effort, nothing is unfavorable. When inner virtue aligns, right action flows naturally without artificial striving." },
      2: { explain: "Six in the third (六三): Containing inner brilliance, one perseveres. Serving in affairs without visible achievement — the outcome is still good. Conceal talents until the right moment." },
      3: { explain: "Six in the fourth (六四): Tie up the bag — neither blame nor praise. Cautious restraint when timing is wrong protects against error." },
      4: { explain: "Six in the fifth (六五): Yellow lower garment — supreme good fortune. Inner beauty of virtue shines through humble outward form." },
      5: { explain: "Six at the top (上六): Dragons battle in the wilderness, their blood dark and yellow. Extreme passivity without judgment leads to conflict and danger." }
    }
  },

  1: { /* 山地剥 KW#23, 艮上坤下 */
    name: "Bō — Splitting Apart (Mountain over Earth)",
    guaciExplain: "Not favorable to go anywhere. Things are collapsing — stay put and consolidate what remains.",
    xiangExplain: "The mountain rests upon the earth — wind and rain erode and strip away. The noble person, observing crumbling cliffs, strengthens solidarity with the people so they may dwell in security.",
    modern: { career: "Your career faces erosion. Don't push forward — consolidate and protect your position. Wait for the cycle to turn.", wealth: "Financial losses likely. Tighten your belt, reduce investments, hold cash. Prudent conservation prevents greater losses.", love: "Relationships face external pressures. Third-party interference possible. Hold steady; avoid rash decisions during instability.", health: "Existing health issues may worsen. Focus on rest and recovery. Prevention is critical now.", interpersonal: "Be cautious — not everyone with friendly faces has good intentions. Stay close to true allies." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): The bed splits at the legs — neglecting foundations brings misfortune. When the base is destroyed, everything above collapses." },
      1: { explain: "Six in the second (六二): The bed splits at the frame — neglecting support brings misfortune. Deterioration reaches the structure itself." },
      2: { explain: "Six in the third (六三): Splitting it — no blame. Breaking away from the unsalvageable is correct. Release what cannot be saved." },
      3: { explain: "Six in the fourth (六四): The bed splits through to the skin — misfortune. Deterioration reaches your very person. Immediate protection needed." },
      4: { explain: "Six in the fifth (六五): A string of fish — favor through palace ladies. Nothing unfavorable. Even in decline, small blessings provide sustenance." },
      5: { explain: "Nine at the top (上九): A great fruit remains uneaten. The noble person gains a carriage; the petty person's house collapses. What is essential endures when the inessential crumbles." }
    }
  },

  2: { /* 水地比 KW#8, 坎上坤下 */
    name: "Bǐ — Holding Together (Water over Earth)",
    guaciExplain: "Union brings good fortune. Examine the divination — is there fundamental virtue and steadfastness? No blame. The restless come; those who delay face misfortune. Belonging brings strength.",
    xiangExplain: "Water on the earth — intimately close, inseparable. The ancient kings established states and maintained close relations with feudal lords. Connection is the foundation of civilization.",
    modern: { career: "Time for teamwork and alliances. Seek mentors, collaborators, strategic partners. Your network is your greatest asset. The right partnership accelerates growth beyond solo capability.", wealth: "Shared investments and partnerships are favorable. Pool resources with trusted allies for mutual benefit.", love: "Excellent time for deepening commitment. Whether single or partnered, energy supports genuine, lasting intimacy.", health: "Holistic health through balanced living — mind, body, and social connection all matter. Community heals.", interpersonal: "Your relationships are the foundation of wellbeing. Nurture genuine connections. A few true allies outweigh a thousand acquaintances." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Hold to him with sincerity — no blame. Like a vessel filled to the brim, sincerity overflows and attracts unexpected blessings." },
      1: { explain: "Six in the second (六二): Hold to him from within — perseverance brings good fortune. Union from inner conviction and shared values is lasting." },
      2: { explain: "Six in the third (六三): Holding to the wrong people — misfortune. Aligning with wrong allies brings harm. Choose companions with discernment." },
      3: { explain: "Six in the fourth (六四): Hold to him from without — perseverance brings good fortune. Even those outside the inner circle find blessing through loyal association." },
      4: { explain: "Nine in the fifth (九五): Manifest holding together — the king lets those who flee escape. Inclusive, non-coercive leadership lets people freely choose to belong." },
      5: { explain: "Six at the top (上六): Holding together without a head — misfortune. Union without proper leadership is chaos. True community needs shared purpose and wise guidance." }
    }
  },

  3: { /* 风地观 KW#20, 巽上坤下 */
    name: "Guān — Contemplation (Wind over Earth)",
    guaciExplain: "The ablution is made but not yet the offering — with sincerity, one gazes upward. Contemplation before action; observation before judgment. Your example is watched by all.",
    xiangExplain: "Wind moves across the earth — touching everything. The ancient kings examined regions, observed people, and established guidance. Like wind reaching every blade of grass, careful observation reaches everywhere.",
    modern: { career: "Before making moves, observe carefully. Watch the market, understand politics, learn unwritten rules. Contemplation prevents costly mistakes. Others watch your example too.", wealth: "Thorough research before any financial commitment. Due diligence is essential. Observe before you invest.", love: "Watch how your partner treats others, handles stress, keeps promises. Observation reveals character. Contemplate before deeper commitment.", health: "Listen to your body carefully. Observe patterns — when do you feel best? Detailed observation informs effective treatment.", interpersonal: "Be a better observer. Watch body language, listen to tone, notice actions not just words. Your conduct is being observed too." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Boyish observation — for the petty person, no blame; for the noble, humiliation. Superficial observation is forgivable in the inexperienced, shameful in those who should know better." },
      1: { explain: "Six in the second (六二): Peering through a crack — favorable for a woman's perseverance. Narrow observation; sometimes appropriate for constrained roles." },
      2: { explain: "Six in the third (六三): Observing my own life — advancing or retreating. Self-examination determines whether to move forward or withdraw." },
      3: { explain: "Six in the fourth (六四): Observing the kingdom's glory — favorable to be the king's guest. Broad, elevated observation brings insight." },
      4: { explain: "Nine in the fifth (九五): Observing my own life — the noble person has no blame. The leader's self-examination protects against error." },
      5: { explain: "Nine at the top (上九): Observing their lives — the noble person has no blame. Observing others with wisdom and compassion completes contemplation." }
    }
  },

  4: { /* 雷地豫 KW#16, 震上坤下 */
    name: "Yù — Enthusiasm (Thunder over Earth)",
    guaciExplain: "Favorable to establish lords and mobilize armies. Enthusiasm and joyful movement — but only when grounded in righteousness. Impulsive excitement without foundation brings regret.",
    xiangExplain: "Thunder bursts from the earth — explosive, joyful energy. The ancient kings composed music and honored virtue. Enthusiasm channeled into creative expression honors heaven.",
    modern: { career: "Your enthusiasm is your greatest asset — authentic passion attracts opportunity. Back excitement with solid preparation. Let energy inspire while results earn respect.", wealth: "Markets are buoyant. Ride the wave but stay grounded. Balance optimism with discipline.", love: "Passion and excitement characterize romance. Enjoy it! But ensure it's built on genuine compatibility, not just excitement.", health: "Energy levels high — channel vitality into positive health habits. Joyful movement is more sustainable than grim workouts.", interpersonal: "Your positive energy is contagious. People gravitate toward genuine enthusiasm. Share joy generously — it multiplies." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Proclaiming enthusiasm — misfortune. Broadcasting excitement before it's grounded invites disappointment." },
      1: { explain: "Six in the second (六二): Firm as a rock — perseverance brings good fortune. Steadfastness amid excitement is rare and valuable." },
      2: { explain: "Six in the third (六三): Looking up with enthusiasm — regret. Hesitating — regret. Passive enthusiasm waiting for approval brings regret." },
      3: { explain: "Nine in the fourth (九四): The source of enthusiasm — great achievement. Friends gather around. Being the genuine source of positive energy brings accomplishment." },
      4: { explain: "Six in the fifth (六五): Persevering through illness — yet not dying. When enthusiasm meets difficulty, steadfast commitment ensures survival." },
      5: { explain: "Six at the top (上六): Darkened enthusiasm — change course and there is no blame. Willingness to correct course redeems misguided enthusiasm." }
    }
  },

  5: { /* 火地晋 KW#35, 离上坤下 */
    name: "Jìn — Progress (Fire over Earth)",
    guaciExplain: "The prince is honored with horses in great number — in a single day granted audience three times. Rapid advancement comes to those whose virtue shines brightly.",
    xiangExplain: "Brightness rises above the earth — the sun ascending. The noble person cultivates brilliant virtue within. Like the rising sun, inner radiance manifests as outer advancement.",
    modern: { career: "Rapid progress and recognition are coming. Your talents are noticed by those in power. Stay grounded — pride before a fall is real.", wealth: "Financial progress accelerates. Income rises, investments appreciate. Don't inflate lifestyle unsustainably with sudden prosperity.", love: "Relationship progresses quickly toward commitment. Exciting but ensure genuine compatibility underpins the momentum.", health: "Vitality rising — good time for significant health improvements while momentum is strong.", interpersonal: "Social standing rises. More people seek your company. Choose new connections wisely — not all celebrants have pure intentions." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Advancing but blocked — perseverance brings good fortune. Without trust, be calm — no blame. Early obstacles in advancement." },
      1: { explain: "Six in the second (六二): Advancing but worried — perseverance brings good fortune. Receiving great blessing from the ancestral mother." },
      2: { explain: "Six in the third (六三): All agree — regret disappears. When the collective supports advancement, obstacles dissolve." },
      3: { explain: "Nine in the fourth (九四): Advancing like a hamster — perseverance brings danger. Scrabbling for rapid, petty advancement invites disaster." },
      4: { explain: "Six in the fifth (六五): Regret disappears. Neither gain nor loss matters — going forward, good fortune. Release anxiety; confident progress." },
      5: { explain: "Nine at the top (上九): Advancing with horns — only for self-discipline. Danger but good fortune. Aggressive advancement only appropriate for self-correction." }
    }
  },

  6: { /* 泽地萃 KW#45, 兑上坤下 */
    name: "Cuì — Gathering Together (Lake over Earth)",
    guaciExplain: "Success. The king approaches his temple. Favorable to see the great person. Success through gathering — of people, resources, and shared purpose. Devotion brings unity.",
    xiangExplain: "A lake gathers upon the earth — water collects. The noble person prepares against unexpected dangers. Like water pooling in a basin, people gather for shared purpose — and the gathering must be protected.",
    modern: { career: "Teams form, talent coalesces, resources pool. Be at the center of the gathering. Common purpose unites disparate individuals into something greater.", wealth: "Pooling resources multiplies financial power. Joint ventures, investment clubs, and cooperative models are favored.", love: "Gathering with those sharing your values creates opportunity. For partnered people, shared purpose deepens bonds.", health: "Community-based health practices — group fitness, wellness circles — provide motivation and accountability.", interpersonal: "Gather your tribe. Host events, initiate gatherings. Be the center around which community crystallizes. Together you are stronger." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): With trust but not to the end — now gathering, now scattering. Inconsistent commitment scatters what could have gathered." },
      1: { explain: "Six in the second (六二): Drawn along — good fortune, no blame. With sincerity, even a small offering is favorable." },
      2: { explain: "Six in the third (六三): Gathering amid sighs — nothing favorable. Going forward, no blame but some humiliation. Half-hearted gathering produces poor results." },
      3: { explain: "Nine in the fourth (九四): Great good fortune, no blame. Being the catalyst for gathering others brings the greatest blessing." },
      4: { explain: "Nine in the fifth (九五): Gathering through position — no blame. Without trust, perpetual perseverance dissolves regret. Leadership that gathers; virtue restores trust." },
      5: { explain: "Six at the top (上六): Sighing and weeping — no blame. Even shared lament is a form of gathering; shared emotion unites." }
    }
  },

  7: { /* 天地否 KW#12, 乾上坤下 */
    name: "Pǐ — Stagnation (Heaven over Earth)",
    guaciExplain: "The malign blocks the way. The great departs, the small arrives. Heaven and earth out of communication — unfavorable for the noble person's perseverance. A time of blockage and separation.",
    xiangExplain: "Heaven and earth do not communicate — obstruction. The noble person restrains virtue to avoid harm, refusing honor from wealth and position. When the world is out of joint, integrity is preserved through withdrawal.",
    modern: { career: "Nothing moves forward. Key people don't respond, projects stall. This is the season, not your fault. Preserve integrity, work quietly, trust the cycle will turn.", wealth: "Financial blockage — deals fall through, payments delayed. Hold cash and wait for clearer conditions.", love: "Communication has broken down. Force and accusation deepen blockage. Gentle patience creates conditions for reconnection.", health: "Body energy feels blocked or stagnant. Focus on gentle movement, proper rest, patience — not aggressive treatments.", interpersonal: "Social connections feel blocked. Use solitude for reflection and self-cultivation rather than desperate connection-seeking." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Pulling out a reed brings others — perseverance brings good fortune. Even in stagnation, right action creates positive chains." },
      1: { explain: "Six in the second (六二): Embracing the burden — the petty succeed; the great succeed through negation. Noble persons find different success through principled withdrawal." },
      2: { explain: "Six in the third (六三): Embracing shame — knowing the time's humiliation yet enduring with dignity." },
      3: { explain: "Nine in the fourth (九四): With heaven's mandate, no blame. Allies share the blessing. When timing shifts, those who preserved integrity find vindication." },
      4: { explain: "Nine in the fifth (九五): Ending stagnation — good fortune for the great person. Vigilant effort restores order and communication." },
      5: { explain: "Nine at the top (上九): Overturning stagnation — first blockage, then joy. When obstruction breaks, relief is profound." }
    }
  },

  /* ===== 艮宫 ===== */
  8: { /* 地山谦 KW#15, 坤上艮下 */
    name: "Qiān — Modesty (Earth over Mountain)",
    guaciExplain: "Modesty brings success. The noble person carries things through to completion. When the great makes itself small and the high makes itself low, lasting achievement follows.",
    xiangExplain: "A mountain within the earth — the great bows beneath. The noble person reduces excess and increases insufficiency, weighing things to balance. The mountain, though mighty, humbly places itself beneath the earth.",
    modern: { career: "The most effective strategy is genuine humility. Let work speak; don't trumpet achievements. The colleague quietly enabling team success is more valuable than the credit-claimer.", wealth: "Modest, steady financial practices build lasting wealth. The truly wealthy don't need to prove it. Understated management preserves and grows resources.", love: "Strongest relationships are built on mutual humility — admitting fault, yielding gracefully. Arrogance destroys intimacy; humility deepens it.", health: "A humble approach to health — listening to body signals, accepting limitations, gradual improvement — is more sustainable than extreme regimens.", interpersonal: "Genuine humility is magnetic. People gravitate to those who don't need to be center, who listen more than speak, who celebrate others' success." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): The modest person, modest in conduct — crossing the great river brings good fortune. Humble enough to attempt great things without arrogance." },
      1: { explain: "Six in the second (六二): Proclaiming modesty — perseverance brings good fortune. When humility is genuine and consistent, it radiates and attracts blessing." },
      2: { explain: "Nine in the third (九三): The modest person, toiling with merit — completion brings good fortune. The hardest worker who takes least credit earns deepest respect." },
      3: { explain: "Six in the fourth (六四): Nothing unfavorable — spreading modesty everywhere. Humility applied consistently protects against error." },
      4: { explain: "Six in the fifth (六五): Not enriched by neighbors — favorable to attack. When even humility is exploited, firm action becomes appropriate." },
      5: { explain: "Six at the top (上六): Proclaiming modesty — favorable to mobilize armies. When humility must be defended, even force serves what is right." }
    }
  },

  9: { /* 艮为山 KW#52, 艮上艮下 */
    name: "Gèn — Keeping Still (Mountain)",
    guaciExplain: "Keeping the back still so one no longer feels the body. Walking in the courtyard without seeing the people. No blame. Stillness of the mind — when you stop at the right place, inner peace follows.",
    xiangExplain: "Mountains standing together — this is Gen. The noble person's thoughts do not go beyond their position. Like mountains resting in their place, each thing finds peace in its proper boundary.",
    modern: { career: "Stop pushing. Be still. The best career move right now may be no move at all. Stillness allows clarity about what truly matters to emerge.", wealth: "Stop chasing returns. Be still with your finances. Resist the urge to constantly trade or adjust. Stillness reveals what investments truly matter.", love: "Stop pursuing. Be still. In the quiet space between actions, genuine connection can finally be felt. Stillness in love is not absence — it's presence.", health: "Your body needs stillness more than activity right now. Rest, meditation, quiet — the healing power of not-doing is underrated.", interpersonal: "Know when to stop. Not every social invitation needs accepting, not every argument needs engaging. Stillness in relationships creates space for wisdom." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Keeping the toes still — no blame. It is favorable to persevere. Stop at the very beginning before momentum carries you into error." },
      1: { explain: "Six in the second (六二): Keeping the calves still — cannot rescue those you follow; the heart is unhappy. Stopping midway is uncomfortable but necessary." },
      2: { explain: "Nine in the third (九三): Keeping the hips still — making the spine rigid. Danger and suffocation of the heart. Forced stillness that creates tension rather than peace." },
      3: { explain: "Six in the fourth (六四): Keeping the trunk still — no blame. Stillness of the body's core; the self rests in its center." },
      4: { explain: "Six in the fifth (六五): Keeping the jaws still — words are orderly. Regret disappears. Stillness in speech; each word intentional." },
      5: { explain: "Nine at the top (上九): Generous stillness — good fortune. The highest stillness is not rigid but spacious, peaceful, and blessing." }
    }
  },

  10: { /* 水山蹇 KW#39, 坎上艮下 */
    name: "Jiǎn — Obstruction (Water over Mountain)",
    guaciExplain: "Obstruction. The southwest is favorable; the northeast is not. Favorable to see the great person. Perseverance brings good fortune. Difficult terrain ahead — seek the path of least resistance.",
    xiangExplain: "Water on the mountain — difficult terrain. The noble person turns inward and cultivates virtue. When the outer path is blocked, the inner path opens. Obstruction redirects toward growth.",
    modern: { career: "You face significant obstacles. The direct path is blocked. Turn inward — build skills, strengthen character. The detour may become the more meaningful journey.", wealth: "Financial obstacles block easy progress. The southwest (metaphorically: receptive, cooperative approach) is favored over the northeast (aggressive, forceful).", love: "Obstacles in the relationship. Forcing through creates damage. Turn inward — work on yourself rather than demanding changes from partner.", health: "Physical obstacles — recovery is slower than hoped. Patience with your body's timeline is itself medicine.", interpersonal: "Difficult people block your social path. Rather than fighting them, redirect your energy to those who support your growth." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Going brings obstruction; coming back earns praise. Retreating from obstacle brings recognition for wisdom." },
      1: { explain: "Six in the second (六二): The king's servant faces obstruction after obstruction — not from personal fault. Obstacles come with the position, not from error." },
      2: { explain: "Nine in the third (九三): Going brings obstruction; coming back, one returns. Accepting the obstacle and returning home is sometimes the wisest course." },
      3: { explain: "Six in the fourth (六四): Going brings obstruction; coming brings connection. Retreat from obstacle creates unexpected alliance." },
      4: { explain: "Nine in the fifth (九五): Great obstruction — friends come. The greatest obstacles attract the truest helpers." },
      5: { explain: "Six at the top (上六): Going brings obstruction; coming brings great good fortune. Favorable to see the great person. The final return from obstruction yields profound blessing." }
    }
  },

  11: { /* 风山渐 KW#53, 巽上艮下 */
    name: "Jiàn — Gradual Development (Wind over Mountain)",
    guaciExplain: "The maiden is given in marriage — good fortune. Perseverance brings advantage. Like a tree growing on a mountain, gradual, steady development brings lasting success.",
    xiangExplain: "Wind above the mountain — trees grow slowly on high places. The noble person abides in virtue and improves customs. Gradual, patient cultivation transforms society.",
    modern: { career: "Career grows steadily, not explosively. Like a tree on a mountain, your growth is slow but deep-rooted. Don't compare to others' speed — your path is about durability.", wealth: "Wealth accumulates gradually. Steady saving, patient investing, compound growth. The tortoise beats the hare in finance.", love: "Love develops step by step — courtship, commitment, deepening. Rushing stages creates instability. Let each stage complete naturally.", health: "Health improves gradually. Small, consistent habits compound into lasting wellbeing. Quick fixes fail; steady practice endures.", interpersonal: "Relationships deepen slowly through shared experience. Don't force intimacy — let trust build naturally over time. The strongest bonds grow like old trees." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Wild geese gradually approach the shore — the young son is in danger. There are words, but no blame. Early, tentative progress is vulnerable but forgivable." },
      1: { explain: "Six in the second (六二): Wild geese gradually approach the rocky cliff — eating and drinking joyfully. Good fortune. Finding sustenance and joy at each stage of the journey." },
      2: { explain: "Nine in the third (九三): Wild geese gradually approach the high plateau — the husband goes to war and does not return. The wife is pregnant but does not give birth. Misfortune. Progress interrupted by external events." },
      3: { explain: "Six in the fourth (六四): Wild geese gradually approach the trees — perhaps finding a flat branch. No blame. Finding a temporary, imperfect perch — adequate for now." },
      4: { explain: "Nine in the fifth (九五): Wild geese gradually approach the summit — the wife does not conceive for three years. Ultimately nothing can stop it. Good fortune. Patient waiting through barren periods — the summit will be reached." },
      5: { explain: "Nine at the top (上九): Wild geese gradually approach the great height — their feathers can be used for ceremonial ritual. Good fortune. The completed journey provides value that serves higher purposes." }
    }
  },

  12: { /* 雷山小过 KW#62, 震上艮下 */
    name: "Xiǎo Guò — Small Excess (Thunder over Mountain)",
    guaciExplain: "Small excess brings success. Perseverance is favorable. Small matters may be done; great matters should not be. A slight overcorrection is sometimes needed — but don't overdo it.",
    xiangExplain: "Thunder above the mountain — a slight excess of sound and force. The noble person, in conduct, exceeds in humility; in mourning, exceeds in grief; in expenditure, exceeds in frugality. Better to slightly exceed in virtue than fall short.",
    modern: { career: "A slight overcorrection is needed. You've been too cautious — take a small risk. But don't swing to recklessness. Small excess, not large.", wealth: "Slightly exceed your savings target. A small surplus is better than a small deficit. But don't become miserly — small excess in prudence, not in deprivation.", love: "Slightly exceed in showing care. Small extra gestures of love compensate for natural tendency toward taking each other for granted.", health: "Slightly exceed in health practices. An extra walk, one more vegetable, ten minutes more sleep. Small excess in self-care pays off.", interpersonal: "Slightly exceed in kindness. Going a small step beyond what's expected in generosity and consideration builds lasting goodwill." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): A bird flying brings misfortune. Do not exceed in what should not be exceeded." },
      1: { explain: "Six in the second (六二): Passing by one's grandfather, meeting one's grandmother. Not reaching the prince, meeting his minister. No blame. The modest connection serves where the grand one fails." },
      2: { explain: "Nine in the third (九三): Not exceeding in defense — someone might stab you in the back. Misfortune. Failure to slightly exceed in caution invites harm." },
      3: { explain: "Nine in the fourth (九四): No blame. Not exceeding in meeting — going brings danger; caution is required. Do not persist. Moderation in encounter; restraint protects." },
      4: { explain: "Six in the fifth (六五): Dense clouds from the west but no rain. The prince shoots the hawk in the cave — the arrow finds its mark. Preparation without result until the right target appears." },
      5: { explain: "Six at the top (上六): Not meeting but passing by — the bird flies away. Misfortune — this is calamity from error. Excessive avoidance becomes its own disaster." }
    }
  },

  13: { /* 火山旅 KW#56, 离上艮下 */
    name: "Lǚ — The Wanderer (Fire over Mountain)",
    guaciExplain: "The wanderer — success through small matters. Perseverance brings good fortune to the wanderer. A stranger in a strange land, traveling light, succeeds through adaptability and small steps.",
    xiangExplain: "Fire on the mountain — a traveler's campfire that moves on. The noble person is clear and careful in applying penalties and does not prolong litigation. Like a traveler, do not stay long in one dispute.",
    modern: { career: "You may feel like a stranger in your workplace or industry. Travel light — avoid heavy emotional investment in temporary situations. Adaptability is success.", wealth: "Financial resources are for the journey, not the destination. Travel light financially — avoid heavy debt or illiquid investments right now.", love: "You may feel like a wanderer in love — unattached or feeling distant even in relationship. This phase teaches self-sufficiency before deep connection.", health: "Treat your body as a traveler's camp — keep it clean, functional, and ready to move. Light, portable health practices serve better than elaborate routines.", interpersonal: "Like a wanderer in a new town, be polite to all, close to few. Not every connection needs to be permanent. Some relationships are beautiful precisely because they're temporary." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): The wanderer occupied with trivial matters — this brings calamity. Petty preoccupations while traveling bring disaster." },
      1: { explain: "Six in the second (六二): The wanderer arrives at an inn — carrying his belongings. Gaining a young servant's loyalty. Perseverance. Finding temporary shelter and helpful companions." },
      2: { explain: "Nine in the third (九三): The wanderer's inn burns — he loses his young servant. Perseverance brings danger. Losing what little stability you had through carelessness." },
      3: { explain: "Nine in the fourth (九四): The wanderer rests in a shelter — obtaining an axe. But my heart is not glad. Having resources but lacking the inner peace to enjoy them." },
      4: { explain: "Six in the fifth (六五): Shooting a pheasant — one arrow is lost. Ultimately this brings praise and office. A small sacrifice leads to significant recognition." },
      5: { explain: "Nine at the top (上九): The bird's nest burns — the wanderer first laughs, then weeps. Losing the ox at the pasture. Misfortune. Overconfidence leading to catastrophic loss of what sustains you." }
    }
  },

  14: { /* 泽山咸 KW#31, 兑上艮下 */
    name: "Xián — Influence (Lake over Mountain)",
    guaciExplain: "Influence — success with perseverance. Taking a maiden as wife brings good fortune. Mutual attraction and influence between complementary forces — the universal law of relationship.",
    xiangExplain: "Lake upon the mountain — water moistens the heights. The noble person receives others with humility and openness. Like the mountain receiving the lake's moisture, openness to influence enriches all.",
    modern: { career: "Your influence grows through genuine connection, not force. Like water on a mountain — influence through gentle, persistent presence rather than aggressive assertion.", wealth: "Financial influence comes through attraction, not pursuit. Build something valuable and people will seek you out. Let wealth come to you.", love: "Mutual attraction and influence — the universal dance of relationship. Let feelings develop naturally. The best love is magnetic, not forced.", health: "Holistic health through balanced influence — each system of the body affects others. Treat the whole, not isolated symptoms.", interpersonal: "Your greatest social influence comes through openness and receptivity, not dominance. Like the mountain receiving the lake, let others' perspectives enrich you." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Influence in the big toe. The first stirring of connection — subtle, tentative." },
      1: { explain: "Six in the second (六二): Influence in the calves — misfortune. Staying still brings good fortune. Impulsive response to attraction leads to misfortune." },
      2: { explain: "Nine in the third (九三): Influence in the thighs — holding to what follows. Going forward brings humiliation. Following every impulse of attraction leads to shame." },
      3: { explain: "Nine in the fourth (九四): Perseverance brings good fortune. Regret disappears. Going back and forth — friends follow your thoughts. Steady, sincere influence attracts genuine followers." },
      4: { explain: "Nine in the fifth (九五): Influence in the back of the neck — no regret. Influence that affects the core but is not visible; subtle, powerful, blameless." },
      5: { explain: "Six at the top (上六): Influence in the cheeks, jaws, and tongue. Mere words — superficial influence through speech alone." }
    }
  },

  15: { /* 天山遁 KW#33, 乾上艮下 */
    name: "Dùn — Retreat (Heaven over Mountain)",
    guaciExplain: "Retreat brings success. In small matters, perseverance is favorable. When the mountain withdraws beneath heaven, knowing when to retreat is wisdom, not weakness.",
    xiangExplain: "Heaven above the mountain — the noble person keeps petty people at a distance, not through hatred but through dignified distance. Like heaven's remoteness from the mountain peak, strategic withdrawal preserves integrity.",
    modern: { career: "Strategic retreat is the wisest move. Leave before you're pushed. The dignified exit preserves options that the desperate fight destroys.", wealth: "Pull back from overheated markets. Retreat from risky positions. Preserving capital is more important than squeezing out last gains.", love: "Give space. Chasing someone who's pulling away only accelerates their retreat. Dignified distance sometimes draws them back.", health: "Retreat from poor health habits. Withdraw from environments and routines that drain your vitality. Strategic withdrawal enables recovery.", interpersonal: "Not every battle is worth fighting. Retreat from toxic dynamics with dignity. Distance maintained with grace preserves future reconciliation." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Retreating tail — danger. Do not go anywhere. Retreating too late — when you're the last to leave, danger finds you." },
      1: { explain: "Six in the second (六二): Bound with yellow ox leather — none can loosen it. Firm, resolute commitment to retreat when it's the right course." },
      2: { explain: "Nine in the third (九三): Entangled retreat — danger and distress. Maintaining servants and maids brings good fortune. Burden of attachments during retreat." },
      3: { explain: "Nine in the fourth (九四): Good retreat — for the noble person, good fortune. For the petty person, not so. Those of character find blessing in strategic withdrawal." },
      4: { explain: "Nine in the fifth (九五): Auspicious retreat — perseverance brings good fortune. Celebrated retreat, timed perfectly, is the highest art of withdrawal." },
      5: { explain: "Nine at the top (上九): Noble retreat — nothing unfavorable. The most elevated form of retreat, done with grace and foresight, leaves nothing to regret." }
    }
  },

  /* ===== 坎宫 ===== */
  16: { /* 地水师 KW#7, 坤上坎下 */
    name: "Shī — The Army (Earth over Water)",
    guaciExplain: "The army needs a firm, correct purpose. With a mature, capable leader, there is no blame. The army must be grounded in justice — discipline and proper leadership determine success.",
    xiangExplain: "Water stored within the earth — the masses organized like an army. The noble person nurtures the people and builds collective strength. Leadership is founded on serving those you lead.",
    modern: { career: "Competitive phase. Strategy, teamwork, and discipline determine success. Build your team and lead with integrity. Isolated action invites defeat.", wealth: "Competitive financial environment. Strategic planning matters more than bold moves. Pool resources with trusted partners.", love: "Relationship faces external challenges. A united front, grounded in mutual trust, overcomes outside pressure.", health: "Strengthen defenses through disciplined habits. Regular exercise, nutrition, rest — like training an army.", interpersonal: "Group dynamics require leadership. Fair leadership that serves the collective earns genuine loyalty. Lead by serving." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): The army marches out with discipline — lacking it brings misfortune. Order must be established from the very start." },
      1: { explain: "Nine in the second (九二): In the midst of the army — good fortune, no blame. The king bestows triple commission. Central position of authority brings success." },
      2: { explain: "Six in the third (六三): The army carries corpses — misfortune. Poor leadership burdens the troops with unnecessary casualties." },
      3: { explain: "Six in the fourth (六四): The army retreats to camp — no blame. Knowing when to regroup is strategic virtue, not failure." },
      4: { explain: "Six in the fifth (六五): Birds in the fields — favorable to catch them. Let the eldest lead; the young carry corpses. Choose experienced leadership." },
      5: { explain: "Six at the top (上六): The great ruler issues mandates — founding states. Petty people should not be employed. Wise governance consolidates victory." }
    }
  },

  17: { /* 山水蒙 KW#4, 艮上坎下 */
    name: "Méng — Youthful Folly (Mountain over Water)",
    guaciExplain: "Success. It is not I who seeks the youthful ignoramus — the youthful ignoramus seeks me. First divination, I inform; repeated asking is insolence. Persist in what is correct.",
    xiangExplain: "A spring wells beneath a mountain — water finding its way through rock. The noble person cultivates resolute action to nurture virtue. Like water's persistence, proper guidance brings enlightenment.",
    modern: { career: "You're in a learning phase — embrace it. Seek a mentor; acquire skills. Humble curiosity opens more doors than false confidence.", wealth: "Don't invest in what you don't understand. Take time to educate yourself. A good advisor is worth more than a hot tip.", love: "You may be naive about relationship realities. Take time to truly understand your partner before commitments. Genuine connection requires mutual understanding.", health: "Seek proper medical advice rather than self-diagnosing. Education about your body is the first step to improvement.", interpersonal: "Inexperience may show socially — this is okay. Genuine humility and willingness to learn attract helpful guides." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Developing the ignoramus — favorable to use discipline to remove shackles. Persisting punishment brings humiliation. Discipline opens learning; harshness closes it." },
      1: { explain: "Nine in the second (九二): Bearing with the ignoramus — good fortune. Taking a wife brings good fortune. Patient tolerance creates harmony." },
      2: { explain: "Six in the third (六三): Do not take this woman — seeing a wealthy man, she loses herself. Nothing favorable. Beware those lacking inner stability." },
      3: { explain: "Six in the fourth (六四): Trapped in ignorance — humiliation. Refusing to learn when opportunity is present leads to regret." },
      4: { explain: "Six in the fifth (六五): The youthful ignoramus — good fortune. Acknowledging one's ignorance with sincere humility opens the door to genuine learning." },
      5: { explain: "Nine at the top (上九): Striking the ignoramus — not favorable to oppress; favorable to resist oppression. Discipline must serve liberation, not domination." }
    }
  },

  18: { /* 坎为水 KW#29, 坎上坎下 */
    name: "Kǎn — The Abyss (Water)",
    guaciExplain: "Double abyss — with sincerity, the heart penetrates. Success. Action brings praise. Facing danger with inner truth — the water is deep, but sincerity is a raft.",
    xiangExplain: "Water flows on without end — double abyss. The noble person walks in constant virtue and practices teaching. Like water wearing through stone, persistent virtue overcomes all obstacles.",
    modern: { career: "You're in deep water — facing significant danger or difficulty. Sincerity and inner truth are your lifeline. Don't pretend; your authentic response to crisis defines you.", wealth: "Deep financial danger. Only sincere, fundamental restructuring — not surface fixes — can navigate these waters. Face the true depth of the situation.", love: "Deep emotional waters. Honest acknowledgment of fears and vulnerabilities is the only way through. Surface denial deepens the danger.", health: "Serious health challenge. Face it with complete honesty — about lifestyle, about prognosis, about what needs to change. Sincerity is therapeutic.", interpersonal: "You're navigating emotionally dangerous relationships. Your authentic self — not a performed version — is what keeps you afloat in deep waters." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Double abyss — entering a pitfall. Misfortune. Repeated danger through failing to learn from first experience." },
      1: { explain: "Nine in the second (九二): The abyss has danger — seeking small gains only. Modest goals in dangerous times protect against larger loss." },
      2: { explain: "Six in the third (六三): Coming to the abyss — danger upon danger. Entering the pitfall — do not act. When danger compounds, stillness prevents deeper entanglement." },
      3: { explain: "Six in the fourth (六四): A jug of wine with a basket of food — using simple vessels. Receiving through the window. Ultimately no blame. Humble sincerity accepted through unconventional channels." },
      4: { explain: "Nine in the fifth (九五): The abyss is not full — when level, no blame. Danger not yet at maximum — calm, balanced response prevents overflow." },
      5: { explain: "Six at the top (上六): Bound with black cords, imprisoned behind thorny walls — three years without finding release. Misfortune. Entrapment through persisting in wrong path." }
    }
  },

  19: { /* 风水涣 KW#59, 巽上坎下 */
    name: "Huàn — Dispersion (Wind over Water)",
    guaciExplain: "Dispersion brings success. The king approaches his temple. Favorable to cross the great river. Perseverance brings advantage. When what is stuck disperses, new flow begins.",
    xiangExplain: "Wind moving over water — dispersing what was stagnant. The ancient kings offered sacrifices to the Lord and established temples. Dispersion of blockage through devotion to higher purpose.",
    modern: { career: "What was stuck is finally dispersing. A blocked project, toxic team, or stagnant role is dissolving. Welcome the dispersion — it clears space for what's next.", wealth: "Financial blockage is dispersing. Frozen assets, delayed payments, stuck investments begin to flow again. Facilitate the dispersal.", love: "Emotional blockages in the relationship are dispersing. Old resentments, unspoken grievances finally surface and dissolve. Let them go.", health: "Stagnant conditions (congestion, inflammation, blockage) are dispersing. Support the body's natural clearing process with hydration and gentle movement.", interpersonal: "Stuck social dynamics are dissolving. Awkwardness, grudges, and tensions begin to clear. Let them disperse without clinging to who was right." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Rescuing the horse — good fortune. Swift action to save what can be saved from the dispersion." },
      1: { explain: "Nine in the second (九二): Dispersion — rushing to safety. Regret disappears. Finding solid ground when the old structure dissolves." },
      2: { explain: "Six in the third (六三): Dispersing one's own self — no regret. Letting go of ego and self-concern during dissolution brings unexpected peace." },
      3: { explain: "Six in the fourth (六四): Dispersing the crowd — supreme good fortune. Dispersing toward the heights — beyond ordinary thought. Breaking up groupthink brings highest blessing." },
      4: { explain: "Nine in the fifth (九五): Dispersing sweat — the king's command. Dispersing one's residence — no blame. Great decree amid dissolution; letting go of even the home." },
      5: { explain: "Nine at the top (上九): Dispersing blood — depart and keep distance. No blame. Removing oneself from harmful entanglements; healing through distance." }
    }
  },

  20: { /* 雷水解 KW#40, 震上坎下 */
    name: "Xiè — Deliverance (Thunder over Water)",
    guaciExplain: "Deliverance — the southwest is favorable. Without going anywhere, good fortune comes. Going anywhere brings early good fortune. After thunder and rain, the storm clears — deliverance from trouble.",
    xiangExplain: "Thunder and rain together — deliverance from oppression. The noble person forgives faults and pardons transgressions. Like a storm clearing the air, deliverance brings release and forgiveness.",
    modern: { career: "Relief from a difficult work situation is coming. The storm clears. When deliverance comes, don't dwell on the struggle — move forward with gratitude.", wealth: "Financial pressure is lifting. The crisis resolves, the bill gets paid, the investment recovers. Accept deliverance with grace, not entitlement.", love: "A difficult period in the relationship is resolving. The argument ends, the distance closes. Forgive fully — don't keep score after deliverance.", health: "Recovery from illness or injury accelerates. The body finds release from what was gripping it. Support the healing — don't rush back to full activity.", interpersonal: "A tense social situation resolves. The misunderstanding clears, the grudge releases. Practice the noble person's way: forgive faults, pardon transgressions." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): No blame. The beginning of deliverance — the pressure starts to ease." },
      1: { explain: "Nine in the second (九二): Hunting three foxes in the field — obtaining a yellow arrow. Perseverance brings good fortune. Skillful resolution of multiple hidden problems." },
      2: { explain: "Six in the third (六三): Carrying a burden while riding a carriage — inviting robbers. Perseverance brings humiliation. Ostentation during deliverance attracts new trouble." },
      3: { explain: "Nine in the fourth (九四): Release your big toe — friends come with trust. Let go of small attachments and allies arrive." },
      4: { explain: "Six in the fifth (六五): The noble person alone can deliver — good fortune. Having the petty withdraw. True deliverance comes through character, not circumstance." },
      5: { explain: "Six at the top (上六): The prince shoots a hawk on the high wall — hitting it. Nothing unfavorable. Precise, decisive action removes the last obstacle." }
    }
  },

  21: { /* 火水未济 KW#64, 离上坎下 */
    name: "Wèi Jì — Before Completion (Fire over Water)",
    guaciExplain: "Before completion — success. The young fox, almost across the river, wets its tail — nothing favorable. Almost there but not quite — the danger of premature celebration.",
    xiangExplain: "Fire above water — they do not interact yet. The noble person carefully discerns things and places them in their proper positions. The work is incomplete — discriminate carefully before acting.",
    modern: { career: "You're almost at the finish line — but not there yet. The final push requires more care than the whole journey. Don't celebrate prematurely.", wealth: "A financial goal is nearly achieved — but the last phase is the most dangerous. The young fox drowned with the shore in sight. Stay vigilant.", love: "A relationship is nearly at a new level of commitment — but not yet. The final steps need more care than the entire courtship.", health: "Recovery is nearly complete — the most dangerous moment for relapse. Complete the full course of treatment. Don't stop just because you feel better.", interpersonal: "A social goal is nearly achieved — reconciliation, new connection, resolution. The final steps need careful, deliberate attention. Almost isn't done." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Wetting the tail — humiliation. The very beginning of incompletion — already making mistakes through haste." },
      1: { explain: "Nine in the second (九二): Dragging the wheels — perseverance brings good fortune. Slowing down intentionally when rushing would cause failure." },
      2: { explain: "Six in the third (六三): Before completion — going forward brings misfortune. Favorable to cross the great river. Assess carefully — some paths are blocked, others open." },
      3: { explain: "Nine in the fourth (九四): Perseverance brings good fortune. Regret disappears. Shaking the attacking state — for three years there is reward. Persistent effort through incompletion wins." },
      4: { explain: "Six in the fifth (六五): Perseverance brings good fortune, no regret. The noble person's brilliance — good fortune. Steadfast integrity amid incompletion radiates blessing." },
      5: { explain: "Nine at the top (上九): With trust, drinking wine — no blame. But if one wets the head — losing one's trust. Celebrating modestly is fine; excessive celebration drowns what was almost achieved." }
    }
  },

  22: { /* 泽水困 KW#47, 兑上坎下 */
    name: "Kùn — Exhaustion (Lake over Water)",
    guaciExplain: "Exhaustion — success through perseverance. The great person attains good fortune, no blame. Words are not trusted. When resources are depleted, only inner strength remains — and it is enough.",
    xiangExplain: "The lake dried up above, water depleted below — exhaustion. The noble person risks life to follow their purpose. When all external resources fail, commitment to purpose sustains.",
    modern: { career: "You're exhausted and resources are depleted. Paradoxically, this is when you discover your deepest strength. Words won't convince others — let your endurance speak.", wealth: "Financial exhaustion. Cash is low, options are few. This is when character is revealed. Endure with integrity — the drought eventually breaks.", love: "Relationship exhaustion. Emotional resources depleted. Words of love ring hollow right now. Let steadfast presence, not declarations, carry you through.", health: "Physical or mental exhaustion. Rest deeply — pushing through depletion only deepens it. Your body is telling you something essential.", interpersonal: "Social exhaustion. You've given too much to too many. Pull back. The few who stay when you have nothing to give are your true community." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Sitting exhausted under a bare tree — entering a dark valley. Three years without seeing anyone. Misfortune. Deep, isolated exhaustion — lost in darkness." },
      1: { explain: "Nine in the second (九二): Exhausted amid wine and food — the scarlet knee-bands arrive. Favorable to offer sacrifice. Going forward, misfortune but no blame. Exhaustion amid apparent plenty." },
      2: { explain: "Six in the third (六三): Exhausted among rocks, grasping thorns. Entering the home, not seeing the wife. Misfortune. Trapped in a harsh, barren situation with no comfort." },
      3: { explain: "Nine in the fourth (九四): Slowly coming but exhausted by a golden carriage. Humiliation, but there is completion. External aid arrives too slowly and with too many strings." },
      4: { explain: "Nine in the fifth (九五): Nose and feet cut off — exhausted by scarlet knee-bands. Slowly, joy comes. Favorable to offer sacrifice. The deepest exhaustion precedes the deepest breakthrough." },
      5: { explain: "Six at the top (上六): Exhausted by creepers — wavering and unstable. Saying 'moving brings regret' — if there is regret, going forward brings good fortune. The final trap of exhaustion — indecision. Action, even with regret, brings release." }
    }
  },

  23: { /* 天水讼 KW#6, 乾上坎下 */
    name: "Sòng — Conflict (Heaven over Water)",
    guaciExplain: "With sincerity, obstruction comes. Stay calm and centered — good fortune. Going to the end brings misfortune. Favorable to see the great person; not favorable to cross the great river.",
    xiangExplain: "Heaven and water move in opposite directions — conflict. The noble person is careful in all undertakings from the very beginning. Prevention is better than litigation.",
    modern: { career: "Workplace conflict or legal issues may arise. Seek fair resolution rather than total victory. The colleague you fight today may be your ally tomorrow.", wealth: "Financial or contractual disputes possible. Settle early — the cost of prolonged conflict exceeds potential gain.", love: "Arguments test your relationship. The goal is understanding, not winning. If values fundamentally conflict, acknowledge this honestly.", health: "Stress from conflict manifests physically — headaches, tension, digestive issues. Address root emotional cause. Peace of mind is powerful medicine.", interpersonal: "You may be drawn into others' disputes. Stay neutral when possible. Prioritize fairness over loyalty to one side." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Do not persist in dispute forever — small criticism, but ultimately good fortune. Engage briefly then withdraw." },
      1: { explain: "Nine in the second (九二): Unable to win, return home and hide. The town's three hundred households won't be implicated. Retreating from unwinnable fight protects what matters." },
      2: { explain: "Six in the third (六三): Living on past virtue — persevere in adversity, ultimately good fortune. Humble dedication brings success." },
      3: { explain: "Nine in the fourth (九四): Unable to win, return and accept the decree. Change your approach — good fortune through yielding." },
      4: { explain: "Nine in the fifth (九五): The dispute — supreme good fortune. A wise, impartial judge's resolution brings justice and blessing to all." },
      5: { explain: "Nine at the top (上九): Given a ceremonial belt, but in one court session it's stripped three times. Victory in dispute is fleeting; the price of winning exceeds the reward." }
    }
  },

  /* Continue with all remaining hexagrams... */
  24: { /* 地风升 KW#46, 坤上巽下 */
    name: "Shēng — Ascending (Earth over Wind)",
    guaciExplain: "Ascending — supreme success. See the great person; do not worry. Going south brings good fortune. Like a tree growing from the earth, steady upward progress through nourishment.",
    xiangExplain: "Wood grows within the earth — ascending. The noble person follows virtue, accumulating the small to become great. Like a sapling becoming a forest giant, steady cultivation produces towering results.",
    modern: { career: "Steady upward trajectory. Like a tree growing, your career ascends through accumulated effort, not dramatic leaps. Trust the process.", wealth: "Wealth grows steadily upward. Like compound interest on a tree's growth rings, patient accumulation produces impressive results over time.", love: "Relationship steadily deepens and ascends to new levels. Growth that's gradual is growth that's lasting.", health: "Health steadily improves through consistent cultivation. Small daily disciplines grow into robust vitality.", interpersonal: "Your social standing ascends through genuine virtue, not manipulation. People respect steady, reliable growth more than flashy rises." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Trustworthy ascent — great good fortune. Sincere upward effort from the very beginning brings supreme blessing." },
      1: { explain: "Nine in the second (九二): With sincerity, a small offering is favorable. No blame. Modest, sincere contribution supports ascent." },
      2: { explain: "Nine in the third (九三): Ascending an empty city. No obstacles — the path is astonishingly open." },
      3: { explain: "Six in the fourth (六四): The king uses him on the western mountain — good fortune, no blame. Being employed in service of higher purpose." },
      4: { explain: "Six in the fifth (六五): Perseverance brings good fortune — ascending by steps. Steady, step-by-step ascent is the sustainable path." },
      5: { explain: "Six at the top (上六): Ascending in darkness — perseverance unfavorable. Blind, unchecked ascent without awareness leads to collapse." }
    }
  },
  /* ===== 巽宫 ===== */
  25: { /* 山风蛊 KW#18, 艮上巽下 */
    name: "Gǔ — Decay & Renovation (Mountain over Wind)",
    guaciExplain: "Supreme success. Favorable to cross the great river. Three days before starting, three days after — careful preparation and follow-through. What has decayed must be renovated.",
    xiangExplain: "Wind beneath the mountain — decay sets in where foundation is neglected. The noble person stirs the people and nourishes virtue. Like fresh wind clearing what has become stale.",
    modern: { career: "Your workplace has problems ignored too long. You have opportunity to lead the cleanup. Diagnose before acting; follow through after. The person who fixes what everyone tolerates becomes indispensable.", wealth: "Financial housecleaning overdue. Address debts, fix budgets, clean up neglected accounts. Painful but necessary renovation.", love: "Problems you've both been avoiding are surfacing. This is a gift — honest renovation heals what neglect has damaged.", health: "Chronic health issues needing attention. A thorough health audit reveals what needs fixing. Start the renovation now.", interpersonal: "Toxic relationships or neglected connections need addressing. Some need mending; some need ending. Cleanup frees energy for healthier connections." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Setting right what the father has spoiled — with a son, the father bears no blame. Even danger, ultimately good fortune. Inheriting and fixing problems is the work of a worthy successor." },
      1: { explain: "Nine in the second (九二): Setting right what the mother has spoiled — perseverance not advisable. Some inherited situations require gentle handling rather than forceful correction." },
      2: { explain: "Nine in the third (九三): Setting right what the father spoiled — small regret, no great blame. Correcting entrenched problems is uncomfortable but right." },
      3: { explain: "Six in the fourth (六四): Tolerating what the father spoiled — going forward, humiliation. Allowing decay through inaction brings shame." },
      4: { explain: "Six in the fifth (六五): Setting right what the father spoiled — using praise. Correction done with appreciation for what was good brings success." },
      5: { explain: "Nine at the top (上九): Not serving kings and princes — raising one's own affairs higher. Sometimes the highest path is stepping away from institutional decay to cultivate independent integrity." }
    }
  },

  26: { /* 水风井 KW#48, 坎上巽下 */
    name: "Jǐng — The Well (Water over Wind)",
    guaciExplain: "The well — the city changes, the well does not change. No loss, no gain — those who come and go all draw from the well. Almost reaching the water but the rope is too short — misfortune. Sustaining what sustains all.",
    xiangExplain: "Wood below, water above — the well. The noble person comforts the people and encourages mutual help. Like a well that nourishes the entire community regardless of who draws from it.",
    modern: { career: "Build deep, lasting foundations that serve others. Your true career capital is like a well — not consumed when others draw from it. Share knowledge freely.", wealth: "Build wealth like a well — deep, reliable, accessible. Focus on sustainable income streams that serve others rather than hoarded treasure.", love: "Be a well of emotional nourishment. True love is not depleted by giving — it replenishes from deeper sources. But don't lower a short rope to a deep well.", health: "Health is a deep well — draw consistently from good habits. The well itself (your constitution) is more important than any single bucket of water.", interpersonal: "Be someone others can draw wisdom from. The well nourishes all without discrimination — generous spirit creates lasting community." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): The well is muddy — not drinkable. An old well without birds. Neglected resources that have become unusable through lack of maintenance." },
      1: { explain: "Nine in the second (九二): The well's water falls back — fish are visible. The bucket is broken. Resources wasted through poor tools and methods." },
      2: { explain: "Nine in the third (九三): The well is cleaned but not used — this grieves my heart. It could be drawn from; if the king were wise, all would receive blessing. Good resources going to waste." },
      3: { explain: "Six in the fourth (六四): The well is being lined with bricks — no blame. Repairing and strengthening fundamental resources." },
      4: { explain: "Nine in the fifth (九五): The well's water is cold and clear — it can be drunk. Pure, well-maintained resources that sustain all." },
      5: { explain: "Six at the top (上六): Drawing from the well without covering it — with sincerity, supreme good fortune. Generous sharing of abundance without hoarding brings highest blessing." }
    }
  },

  27: { /* 巽为风 KW#57, 巽上巽下 */
    name: "Xùn — The Gentle (Wind)",
    guaciExplain: "The gentle — success through small matters. Favorable to go somewhere. Favorable to see the great person. Gentle, persistent influence achieves what force cannot.",
    xiangExplain: "Wind following wind — the gentle. The noble person reiterates commands and carries out undertakings. Like wind bending grass without breaking it, gentle persistence shapes the world.",
    modern: { career: "Gentle, persistent influence outperforms aggressive assertion. Like wind shaping landscapes over time, small, consistent actions create massive career results.", wealth: "Gentle financial growth through consistent, small actions. Wind doesn't knock down doors — it patiently wears through mountains.", love: "Gentle, persistent care wins hearts more surely than grand romantic gestures. Be the steady breeze, not the hurricane.", health: "Gentle, consistent health practices transform the body. Soft exercise, gradual dietary shifts, steady sleep habits.", interpersonal: "Gentle influence is the most powerful. Don't argue — persistently model. Like wind, your consistent presence shapes others without confrontation." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Advancing and retreating — the warrior's perseverance is favorable. Knowing when to assert and when to yield." },
      1: { explain: "Nine in the second (九二): The gentle beneath the bed — using scribes and shamans. Good fortune, no blame. Humble influence working through intermediaries." },
      2: { explain: "Nine in the third (九三): Repeated gentleness — humiliation. Excessive yielding becomes its own form of error." },
      3: { explain: "Six in the fourth (六四): Regret disappears. Hunting catches three kinds of game. Gentle persistence finally yields abundant results." },
      4: { explain: "Nine in the fifth (九五): Perseverance brings good fortune. Regret disappears, nothing unfavorable. No beginning but an end. Before changing, three days; after changing, three days. Good fortune. Gentle transformation done thoroughly." },
      5: { explain: "Nine at the top (上九): The gentle beneath the bed — losing the axe. Perseverance brings misfortune. Excessive yielding that loses all power and tools." }
    }
  },

  28: { /* 雷风恒 KW#32, 震上巽下 */
    name: "Héng — Duration (Thunder over Wind)",
    guaciExplain: "Duration — success without blame. Perseverance is favorable. Going somewhere is favorable. Enduring commitment to what is right brings lasting success — the way of marriage and long-term partnership.",
    xiangExplain: "Thunder above, wind below — duration. The noble person stands firm without changing direction. Like the eternal dance of thunder and wind, lasting relationships are built on complementary constancy.",
    modern: { career: "Commit to your path for the long haul. Constancy and persistence matter more than bursts of brilliance. The tortoise's steady pace wins careers, not the hare's sprint.", wealth: "Long-term investing beats short-term trading. Duration — patience, compound interest, steady contribution — creates lasting wealth.", love: "Duration is the essence of lasting love. Not passion that flares and fades, but steady commitment that weathers all seasons. This is the marriage hexagram.", health: "Sustainable health practices maintained over decades create vitality that crash diets and extreme fitness never deliver. Duration over intensity.", interpersonal: "Loyalty and constancy in relationships build the deepest bonds. The friend who shows up consistently over years is worth more than the exciting acquaintance who appears and disappears." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Seeking duration too deeply — perseverance brings misfortune. Nothing favorable. Forcing permanence where it cannot yet exist." },
      1: { explain: "Nine in the second (九二): Regret disappears. Moderation in pursuit of duration prevents error." },
      2: { explain: "Nine in the third (九三): Not constant in virtue — perhaps receiving shame. Perseverance brings humiliation. Inconsistency in character undermines all claims to duration." },
      3: { explain: "Nine in the fourth (九四): No game in the field. Persisting in the wrong place yields nothing despite constancy." },
      4: { explain: "Six in the fifth (六五): Constant in virtue through perseverance — for the wife, good fortune; for the husband, misfortune. Different roles require different expressions of constancy." },
      5: { explain: "Six at the top (上六): Restless duration — misfortune. Constant agitation and change masquerading as commitment." }
    }
  },

  29: { /* 火风鼎 KW#50, 离上巽下 */
    name: "Dǐng — The Cauldron (Fire over Wind)",
    guaciExplain: "The cauldron — supreme good fortune. Success. The sacred vessel that transforms raw ingredients into nourishing food. Civilization and culture simmer in the cauldron.",
    xiangExplain: "Fire over wood — the cauldron. The noble person corrects their position to fulfill destiny. Like fire heating the sacred vessel, right positioning enables transformative work.",
    modern: { career: "You are in a transformative role — cooking something new from raw ingredients. Like the ancient ceremonial cauldrons, your work feeds and sustains your community. Position yourself correctly for maximum impact.", wealth: "Wealth as transformative vessel — money that cooks something nourishing for the world. Investment in culture, education, and community creates lasting value.", love: "Relationship as a cauldron — two people combining their raw ingredients to create something nourishing. The fire of passion must be steady, not explosive.", health: "Your body as a sacred vessel — what you put in transforms into what you become. Honor the vessel through conscious nutrition.", interpersonal: "Your presence is a cauldron — people gather around you and are transformed. Use this influence to nourish, not to manipulate." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): The cauldron overturned — favorable to pour out what is spoiled. Taking a concubine for her son — no blame. Clearing out what no longer serves." },
      1: { explain: "Nine in the second (九二): The cauldron is full — my enemy is ill and cannot reach me. Good fortune. Abundance that protects against threat." },
      2: { explain: "Nine in the third (九三): The cauldron's handle is removed — one's progress is blocked. The pheasant fat is not eaten. Once rain falls, regret disappears. Good fortune. Temporary blockage of nourishment." },
      3: { explain: "Nine in the fourth (九四): The cauldron's legs break — overturning the duke's feast. Punishment and execution. Misfortune. Catastrophic failure of foundation causing loss for all." },
      4: { explain: "Six in the fifth (六五): The cauldron has yellow ears and golden handles — perseverance is favorable. The vessel properly equipped for its sacred function." },
      5: { explain: "Nine at the top (上九): The cauldron has jade handles — great good fortune, nothing unfavorable. The highest refinement of the transformative vessel." }
    }
  },

  30: { /* 泽风大过 KW#28, 兑上巽下 */
    name: "Dà Guò — Great Excess (Lake over Wind)",
    guaciExplain: "Great excess — the ridgepole sags. Favorable to go somewhere. Success. When things are critically out of balance, extraordinary measures are called for.",
    xiangExplain: "The lake rises above the trees — great excess. The noble person stands alone without fear and withdraws from the world without sadness. When circumstances exceed normal bounds, the extraordinary person acts independently.",
    modern: { career: "The situation is critically unbalanced. Normal approaches won't work — you need extraordinary measures. The ridgepole is sagging; reinforce it decisively or the roof collapses.", wealth: "Financial situation critically unbalanced. Extraordinary measures — not tweaks — are needed. Face the true extent of the imbalance.", love: "Relationship critically unbalanced. One partner carrying too much, or dynamic fundamentally skewed. Extraordinary honesty and restructuring needed.", health: "Health critically out of balance. Extreme intervention may be warranted — but with the awareness that excess carries its own danger.", interpersonal: "Social situation critically unbalanced. Stand alone without fear if needed. Withdraw from unhealthy dynamics without sadness." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Using white rushes for a mat — no blame. Extraordinary care in even the smallest matters prevents larger error." },
      1: { explain: "Nine in the second (九二): A withered willow puts forth new shoots — an old man takes a young wife. Nothing unfavorable. Unlikely renewal in a time of excess." },
      2: { explain: "Nine in the third (九三): The ridgepole sags — misfortune. The central support that cannot bear its extraordinary burden." },
      3: { explain: "Nine in the fourth (九四): The ridgepole is raised — good fortune. If there is other involvement, humiliation. The strong central support saves the structure." },
      4: { explain: "Nine in the fifth (九五): A withered willow puts forth flowers — an old woman takes a young husband. No blame, no praise. Unlikely but ultimately neutral renewal." },
      5: { explain: "Six at the top (上六): Crossing the river — the water goes over the head. Misfortune, but no blame. Going to the extreme — dangerous but perhaps necessary." }
    }
  },

  31: { /* 天风姤 KW#44, 乾上巽下 */
    name: "Gòu — Coming to Meet (Heaven over Wind)",
    guaciExplain: "Coming to meet — the maiden is strong. Do not take this maiden as wife. An unexpected encounter with powerful feminine energy — be aware of its strength.",
    xiangExplain: "Heaven above, wind below — coming to meet. The sovereign issues commands and announces them to the four directions. Like the wind carrying heaven's will everywhere, the encounter spreads influence.",
    modern: { career: "An unexpected encounter may dramatically shift your career. A powerful new person or opportunity appears suddenly. Be aware of the power — it can help or overwhelm.", wealth: "An unexpected financial encounter — opportunity or temptation appears suddenly. The maiden is strong: don't underestimate the power of what you're encountering.", love: "A powerful, unexpected romantic encounter. Exciting but potentially overwhelming. The warning 'do not take this maiden' means: be conscious of the power dynamics.", health: "An unexpected health development — positive or concerning. Don't underestimate the body's response to sudden changes.", interpersonal: "A powerful new person enters your social orbit. Their influence will be significant. Be aware — some encounters are better appreciated than embraced." },
    yaoci: {
      0: { explain: "Six at the beginning (初六): Tied to a metal brake — perseverance brings good fortune. Going anywhere brings misfortune. A lean pig runs wild. Restraint of the initial impulse." },
      1: { explain: "Nine in the second (九二): A fish in the wrapping — no blame. Not favorable for guests. Containing the encounter within appropriate boundaries." },
      2: { explain: "Nine in the third (九三): The buttocks have no skin — walking is difficult. Danger but no great blame. The encounter makes progress painful but not fatal." },
      3: { explain: "Nine in the fourth (九四): The wrapper has no fish — this brings misfortune. Missing the encounter through lack of preparation." },
      4: { explain: "Nine in the fifth (九五): A melon wrapped in willows — containing hidden brilliance. Something falls from heaven. Unexpected blessing from the encounter." },
      5: { explain: "Nine at the top (上九): Meeting with horns — humiliation, no blame. The encounter that butts heads — uncomfortable but not wrong." }
    }
  },

  /* ===== 震宫 ===== */
  32: { /* 地雷复 KW#24, 坤上震下 */
    name: "Fù — Return (Earth over Thunder)",
    guaciExplain: "Return — success. Going out and coming in — no harm. Friends come without blame. The path returns; on the seventh day it comes back. After decline, renewal. The turning point has arrived.",
    xiangExplain: "Thunder within the earth — return of yang energy. The ancient kings closed the passes at winter solstice. Commerce did not travel. The turning point is honored with stillness.",
    modern: { career: "After difficulty, renewal begins. The worst is over. Rest now — position yourself for the upswing. The turning point has arrived.", wealth: "Financial recovery begins. Markets turn, opportunities reappear. Don't rush — the upswing needs time. Position patiently.", love: "A relationship that seemed lost may find its way back. Reconciliation possible. Honor the turning point with stillness — don't force it.", health: "Recovery begins. After illness or low energy, your body's healing power awakens. Support with rest, nutrition, gentle movement.", interpersonal: "Old rifts begin to heal. People who drifted away may return. Welcome renewal but don't force it. Be open to new beginnings." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Returning from a short distance — nothing regretful. Supreme good fortune. Catching error early and turning back quickly brings greatest blessing." },
      1: { explain: "Six in the second (六二): The beautiful return — good fortune. Returning to the right path with grace and dignity." },
      2: { explain: "Six in the third (六三): Repeated return — danger but no blame. Returning again and again to wrong paths, yet each time correcting — dangerous but not fatal if awareness persists." },
      3: { explain: "Six in the fourth (六四): Walking in the middle, returning alone. Individual return to right path even when others continue in error." },
      4: { explain: "Six in the fifth (六五): Generous return — no regret. Returning with magnanimity and fullness of heart." },
      5: { explain: "Six at the top (上六): Lost return — misfortune. Calamity from error. Using army, ultimate defeat. Missing the turning point and persisting in error brings prolonged disaster." }
    }
  },

  33: { /* 山雷颐 KW#27, 艮上震下 */
    name: "Yí — Nourishment (Mountain over Thunder)",
    guaciExplain: "Nourishment — perseverance brings good fortune. Observe the jaws — how they provide nourishment. What comes in and goes out of the mouth determines health and character.",
    xiangExplain: "Thunder beneath the mountain — nourishment. The noble person is careful in speech and moderate in eating and drinking. Like thunder stirring beneath stillness, true nourishment comes from mindful consumption.",
    modern: { career: "Nourish your career carefully — what you feed it determines what it becomes. Invest in learning, choose projects wisely, associate with those who feed your growth.", wealth: "Nourish your finances carefully. What you consume financially matters more than what you earn. Mindful spending and investing create lasting wealth.", love: "Nourish your relationship with care. What you feed the relationship — attention, appreciation, patience — determines its health.", health: "Moderate in eating and drinking. True nourishment is about quality, not quantity. Observe what truly feeds your body vs. what merely fills it.", interpersonal: "Be careful in speech — words nourish or poison relationships. What comes out of your mouth shapes your social world as much as what goes in shapes your body." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Abandoning your sacred tortoise, watching me with drooling jaws — misfortune. Forsaking your own source of nourishment to envy others'." },
      1: { explain: "Six in the second (六二): Reversed nourishment — deviating from the norm to seek nourishment above. Going forward, misfortune. Seeking nourishment from wrong sources." },
      2: { explain: "Six in the third (六三): Rejecting nourishment — perseverance brings misfortune. Ten years without benefit. Nothing favorable. Rejecting what truly nourishes brings prolonged barrenness." },
      3: { explain: "Six in the fourth (六四): Reversed nourishment — good fortune. The tiger watches intently; the desire to pursue is strong. No blame. Seeking nourishment from above with fierce focus brings success." },
      4: { explain: "Six in the fifth (六五): Deviating from the norm — perseverance brings good fortune. Not crossing the great river. Modest nourishment; knowing your limits." },
      5: { explain: "Nine at the top (上九): The source of nourishment — danger but good fortune. Favorable to cross the great river. Being the source of nourishment for others involves risk but brings blessing." }
    }
  },

  34: { /* 水雷屯 KW#3, 坎上震下 */
    name: "Zhūn — Difficulty at the Beginning (Water over Thunder)",
    guaciExplain: "Supreme success with perseverance. Do not go anywhere yet. Favorable to establish lords. Like a sprout pushing through hard soil — the struggle of new birth.",
    xiangExplain: "Clouds and thunder — difficulty at the beginning. The noble person manages affairs with careful deliberation. Like spring's first stirrings, energy gathers before breaking through.",
    modern: { career: "Starting a new job or project? Expect turbulence. Like a seedling breaking soil, the initial push requires tremendous energy. Don't be discouraged — every success faces early obstacles.", wealth: "Early investments face difficulties. Conserve resources; avoid overextending. The difficulty is temporary — patient persistence brings returns.", love: "New relationship faces growing pains. Misunderstandings test commitment. If genuine, working through early difficulties creates stronger bonds.", health: "Body adjusting to new routine or treatment — initial difficulty is normal. Give it time and consistent care rather than seeking quick fixes.", interpersonal: "New relationships take time to develop. Don't expect instant harmony. Trust builds through shared experience of overcoming difficulties." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Hovering back and forth — favorable to stay put and establish firm foundations. A strong base is more important than rushing forward." },
      1: { explain: "Six in the second (六二): Halting, circling — not a robber, but a suitor. The woman is chaste; after ten years she promises. True commitment cannot be rushed." },
      2: { explain: "Six in the third (六三): Hunting deer without a guide — going too deep. The noble person abandons the chase. Know when to turn back." },
      3: { explain: "Six in the fourth (六四): Riding, circling back. Seeking union brings good fortune. When the time is right, moving forward brings success." },
      4: { explain: "Nine in the fifth (九五): Storing up blessings — small matters favorable, great matters bring danger. Know your limits." },
      5: { explain: "Six at the top (上六): Riding, circling — tears of blood flow. Pushing forward when the time is utterly wrong brings devastation." }
    }
  },

  35: { /* 风雷益 KW#42, 巽上震下 */
    name: "Yì — Increase (Wind over Thunder)",
    guaciExplain: "Increase — favorable to go somewhere. Favorable to cross the great river. When wind and thunder combine, increase comes through reducing what is above to add to what is below. True increase serves all.",
    xiangExplain: "Wind and thunder — increase. The noble person, seeing good, follows it; having errors, corrects them. Like wind strengthening thunder, increase comes through mutual reinforcement.",
    modern: { career: "A time of increase — promotions, raises, expanding responsibility. True increase comes by serving those below you. The leader who lifts others rises fastest.", wealth: "Financial increase is coming. The key is to share the increase — reducing above to add below. Hoarded increase stagnates; shared increase grows.", love: "The relationship enters a phase of increase — deeper love, greater commitment, more shared joy. Increase comes through giving more, not taking more.", health: "Vitality is increasing. Channel the increase into sustainable habits rather than burning through it. Share your health with others through energy and presence.", interpersonal: "Your social capital is increasing. The secret: celebrate others' good fortune. Seeing good, follow it. Having errors, correct them." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Favorable to undertake great works — supreme good fortune, no blame. The right beginning for increase." },
      1: { explain: "Six in the second (六二): Someone increases you with ten pairs of tortoise shells — none can refuse. Perseverance brings good fortune. The king offers to the Lord. Unexpected abundant blessing." },
      2: { explain: "Six in the third (六三): Increase through unfortunate events — no blame. With sincerity, walk the middle path and report to the prince. Even difficulty becomes increase when handled correctly." },
      3: { explain: "Six in the fourth (六四): Walking the middle path, reporting to the prince — he follows. Favorable to move the capital. Wise counsel that shifts the center of power." },
      4: { explain: "Nine in the fifth (九五): With sincere heart — do not ask; supreme good fortune. Sincere kindness brings increase without needing to request it." },
      5: { explain: "Nine at the top (上九): No one increases you — someone strikes you. The heart is not constant. Misfortune. When increase stops and loss begins, inconstancy is the cause." }
    }
  },

  36: { /* 震为雷 KW#51, 震上震下 */
    name: "Zhèn — The Arousing (Thunder)",
    guaciExplain: "The arousing — success. Thunder comes — 'Ah!' then laughter — 'Ha ha!' The shock that startles and then releases. Facing sudden disturbance with equanimity brings success.",
    xiangExplain: "Repeated thunder — the arousing. The noble person, with fear and trembling, examines their life and corrects their errors. Like thunder that startles then passes, shock awakens self-reflection.",
    modern: { career: "Sudden shock or disruption in your career — reorganization, unexpected change, surprising news. The initial 'Ah!' of fright becomes 'Ha ha!' of relief. Face it with equanimity.", wealth: "Financial shock — market crash, sudden expense, investment surprise. The response matters more than the event. Examine and correct.", love: "Sudden shock in relationship — surprising revelation, unexpected crisis. The thunder tests the foundation. Let it awaken deeper honesty and correction.", health: "Health shock — unexpected diagnosis, sudden symptom. Don't panic. Examine your life, correct errors. The shock is an awakening.", interpersonal: "Sudden social disruption — conflict, betrayal, surprising news. Respond with trembling awareness, not reactive panic. Examine and correct." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Thunder comes — 'Ah!' then laughter — 'Ha ha!' Good fortune. The shock that startles and releases — natural response to sudden change." },
      1: { explain: "Six in the second (六二): Thunder comes — danger. Losing treasures, climbing nine hills. Do not pursue; on the seventh day they return. What is lost in shock will return in time." },
      2: { explain: "Six in the third (六三): Thunder rolls — rousing but without error. The shock that stirs but does not throw off course." },
      3: { explain: "Nine in the fourth (九四): Thunder sinks into the mud. Shock that gets stuck — unable to move forward or release." },
      4: { explain: "Six in the fifth (六五): Thunder goes and comes — danger. But no loss — there is work to be done. Repeated shock that threatens but does not ultimately harm; business continues." },
      5: { explain: "Six at the top (上六): Thunder brings ruin — terrified, looking around. Going forward, misfortune. If the shock has not reached you but only your neighbors, no blame. Marriage brings talk. The shock that devastates — but if you're not the epicenter, learn from others' experience." }
    }
  },

  37: { /* 火雷噬嗑 KW#21, 离上震下 */
    name: "Shì Hé — Biting Through (Fire over Thunder)",
    guaciExplain: "Biting through — success. Favorable to administer justice. An obstacle blocks the way — bite through it decisively. Legal matters and enforcement are favored.",
    xiangExplain: "Thunder and lightning — biting through. The ancient kings clarified penalties and promulgated laws. Like teeth biting through an obstruction, clear justice removes what blocks the path.",
    modern: { career: "Something blocks your progress — a difficult person, stalled project, competitive threat. Address it directly, firmly, and fairly. The hard conversation you've been avoiding is needed.", wealth: "Financial blockage needs decisive resolution. Legal avenues may be appropriate. Firm, fair action prevents larger losses.", love: "The elephant in the room. The issue you've both avoided blocks growth. Bite through it with honest, firm communication.", health: "A health issue needs decisive attention. Stop putting off that doctor's visit or lifestyle change. Bite through resistance.", interpersonal: "An interpersonal obstacle — unresolved conflict, unspoken grievance. Address it directly, with firmness and fairness." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Feet in stocks — toes disappear. No blame. Minor restraint at the beginning — accept the limitation and learn." },
      1: { explain: "Six in the second (六二): Biting through tender meat — nose disappears. No blame. A soft but messy problem — unpleasant but not wrong." },
      2: { explain: "Six in the third (六三): Biting dried meat — encountering poison. Small humiliation, no blame. Tough, unpleasant work with minor embarrassment." },
      3: { explain: "Nine in the fourth (九四): Biting dried gristly meat — obtaining a bronze arrowhead. The toughest problems yield the most valuable rewards." },
      4: { explain: "Six in the fifth (六五): Biting dried meat — obtaining yellow gold. Perseverance with caution brings no blame. Highest rewards through persistent, careful effort." },
      5: { explain: "Nine at the top (上九): Wearing the cangue — ears disappear. Misfortune. Refusing to hear; stubborn persistence in wrong action leads to entrapment." }
    }
  },

  38: { /* 泽雷随 KW#17, 兑上震下 */
    name: "Suí — Following (Lake over Thunder)",
    guaciExplain: "Following — supreme success with perseverance. No blame. Knowing when to lead and when to follow — adapting to circumstances with wisdom brings highest success.",
    xiangExplain: "Thunder within the lake — following. The noble person goes indoors at nightfall for rest. Following natural rhythms brings peace and effectiveness.",
    modern: { career: "Your career benefits more from strategic following than assertive leadership right now. Find the right mentor, join the right team, align with the right trend. Choose carefully what you follow.", wealth: "Follow market trends rather than fighting them. Adaptability in financial matters brings better returns than stubborn conviction.", love: "Mutual adaptation is the secret to relationship harmony. Sometimes leading, sometimes following — the dance of give and take.", health: "Follow your body's natural rhythms. The most effective health practices work with, not against, your energy cycles.", interpersonal: "Social success through adaptability. Read the room, follow cues, adjust your approach. Flow between different contexts with ease." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): The standard changes — perseverance brings good fortune. Going beyond the gate to associate brings achievement. Adapting position when circumstances shift." },
      1: { explain: "Six in the second (六二): Tied to the young son — losing the mature man. Following the immature while neglecting the wise leads to loss." },
      2: { explain: "Six in the third (六三): Tied to the mature man — losing the young son. Following brings what is sought. Choosing substance over appearance brings genuine gain." },
      3: { explain: "Nine in the fourth (九四): Following brings capture — perseverance brings misfortune. Being led into entrapment through blind following." },
      4: { explain: "Nine in the fifth (九五): Sincere in what is good — good fortune. Following what is genuinely good with wholehearted sincerity." },
      5: { explain: "Six at the top (上六): Grasped and held — bound tightly. The king makes offerings on the western mountain. Total commitment to what you follow." }
    }
  },

  39: { /* 天雷无妄 KW#25, 乾上震下 */
    name: "Wú Wàng — Innocence (Heaven over Thunder)",
    guaciExplain: "Innocence — supreme success with perseverance. If not correct, calamity comes. Not favorable to go anywhere. Natural authenticity brings supreme blessing; scheming brings disaster.",
    xiangExplain: "Thunder rolls beneath heaven — things happen according to their nature. The ancient kings, in accord with seasons, nurtured all things. Authentic action aligned with nature's way.",
    modern: { career: "Best career strategy: authenticity. Work honestly, develop genuine skills, build real relationships. Office politics backfire eventually. Trust that genuine merit is recognized.", wealth: "Honest, straightforward financial practices are the only safe path. Get-rich-quick schemes and artificial structures eventually collapse.", love: "Be genuine. Game-playing and artificial postures destroy connection. The right person loves the real you — and the wrong person wasn't worth pretending for.", health: "Your body knows how to be healthy when you stop interfering. Trust natural processes more than artificial interventions.", interpersonal: "Authenticity attracts genuine connection. Drop the mask — vulnerability and honesty create deeper bonds than any polished facade." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Innocent going — good fortune. Acting without ulterior motives, simply doing what is right." },
      1: { explain: "Six in the second (六二): Not plowing yet reaping; not clearing ground yet harvesting — favorable to go. Don't expect results without effort, but advance when the path is clear." },
      2: { explain: "Six in the third (六三): The innocent suffer calamity — someone tied the cow, a passerby takes it. Sometimes bad things happen to good people — it is not your fault." },
      3: { explain: "Nine in the fourth (九四): Perseverance — no blame. Steadfast innocence, even when tested, protects against error." },
      4: { explain: "Nine in the fifth (九五): The innocent have illness — do not use medicine; there will be joy. Sometimes natural healing surpasses intervention. Trust the process." },
      5: { explain: "Nine at the top (上九): Innocent action — calamity from error. Nothing favorable. Even innocent intentions, with misguided action, can bring disaster. Innocence needs wisdom." }
    }
  },

  /* ===== 离宫 ===== */
  40: { /* 地火明夷 KW#36, 坤上离下 */
    name: "Míng Yí — Darkening of the Light (Earth over Fire)",
    guaciExplain: "Darkening of the light — perseverance through adversity is favorable. When brightness is wounded and obscured by darkness, the wise person hides their light to survive.",
    xiangExplain: "Fire sinks into the earth — the light is darkened. The noble person, among the masses, hides their brilliance yet remains clear within. Like a lamp lowered into a well, light preserved in darkness.",
    modern: { career: "Your talents and achievements are being obscured — perhaps by office politics, perhaps by a toxic boss. Hide your light strategically. This darkness will pass; preserve your brilliance for when it can shine again.", wealth: "Financial resources are hidden or trapped. Don't display wealth in this environment. Preserve it quietly until conditions improve.", love: "The relationship is going through a dark period. Love that was bright is now obscured. Endure with integrity — not all seasons are summer.", health: "Vitality is low; your usual brightness is dimmed. This is not permanent. Rest deeply; preserve energy for recovery.", interpersonal: "In a dark social environment, hide your brilliance. Not everyone can handle your light right now. Find those few who can see in the dark." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Darkening of the light in flight — lowering wings. The noble person on a journey, three days without eating. Going somewhere, there are words of criticism. Retreat with dignity through difficulty." },
      1: { explain: "Six in the second (六二): Darkening of the light — injured in the left thigh. Using a horse to rescue — good fortune. Injured but still able to help others escape." },
      2: { explain: "Nine in the third (九三): Darkening of the light in the southern hunt — capturing the great chief. Not advisable to persist. Victory in darkness that should not be pressed." },
      3: { explain: "Six in the fourth (六四): Entering the left side of the belly — capturing the heart of the darkening light. Going out through the gate and courtyard. Understanding the darkness from within." },
      4: { explain: "Six in the fifth (六五): Darkening of the light like Prince Ji — perseverance is favorable. The noble who feigned madness to survive tyranny — strategic concealment of wisdom." },
      5: { explain: "Six at the top (上六): Not bright but dark — first ascending to heaven, then falling into the earth. The tyrant who rose to power and then collapsed into darkness." }
    }
  },

  41: { /* 山火贲 KW#22, 艮上离下 */
    name: "Bì — Grace (Mountain over Fire)",
    guaciExplain: "Grace — success. Small matters are favorable. Beauty and adornment enhance what is solid — but form without substance is hollow. Small, beautiful things flourish.",
    xiangExplain: "Fire at the foot of the mountain — radiance beautifies. The noble person clarifies governance but dares not lightly decide litigations. Beauty illuminates but must not substitute for substance.",
    modern: { career: "Presentation matters right now — polish your resume, upgrade professional appearance, refine communication. But packaging without product fails. Enhance substance AND style.", wealth: "Small, aesthetic improvements yield disproportionate returns — branding, presentation. But don't let an investment's shine blind you to its fundamentals.", love: "Romance, beauty, and grace enhance love. Enjoy flowers and candlelight — but don't mistake surface charm for character.", health: "Outer care reflects inner health. Grooming and grace are part of wellbeing. But don't obsess over appearance at the expense of actual health.", interpersonal: "Social grace opens doors. Polish manners, refine conversation, cultivate elegance. But ensure surface charm is backed by genuine kindness." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Adorning the feet — discarding the carriage and walking. Choosing simplicity and substance over ostentatious display." },
      1: { explain: "Six in the second (六二): Adorning the beard — seeking elegance in what naturally grows. Cultivating natural grace rather than artificial decoration." },
      2: { explain: "Nine in the third (九三): Adorned like one bathed in grace — perpetual perseverance brings good fortune. Grace so natural it glows from within." },
      3: { explain: "Six in the fourth (六四): Adorned like a white horse with wings — not a robber but one seeking marriage. Appearances can mislead." },
      4: { explain: "Six in the fifth (六五): Adorned among hills and gardens — the silk offering is meager. Humble but sincere. Small, genuine gestures bring good fortune." },
      5: { explain: "Nine at the top (上九): White adornment — no blame. The highest grace returns to simplicity. Pure, unadorned authenticity is the most beautiful state." }
    }
  },

  42: { /* 水火既济 KW#63, 坎上离下 */
    name: "Jì Jì — After Completion (Water over Fire)",
    guaciExplain: "After completion — success in small matters. Perseverance is favorable. At the beginning, good fortune; at the end, disorder. Success achieved — now the challenge is to maintain it.",
    xiangExplain: "Water above fire — after completion. The noble person contemplates trouble and prepares against it. Like water that can boil over and extinguish the fire, completion contains the seeds of its own undoing.",
    modern: { career: "You've achieved your goal — now comes the harder part: maintaining it. Success breeds complacency; complacency breeds failure. Think about potential problems NOW.", wealth: "Financial goal achieved. The danger: thinking you're done. Completion is a phase, not an endpoint. Prepare for disorder by building reserves.", love: "You've reached a stable, committed place — marriage, deep partnership. Don't relax into complacency. Completion needs continued nurturing.", health: "Health goal achieved — weight lost, condition improved. The hardest part: maintenance. Most people regain what they lost. Prepare against regression.", interpersonal: "A social success achieved — reconciliation, new connection, resolution. Now the work of maintenance begins. Completion is not the end." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Dragging the wheels — wetting the tail. No blame. Slowing down at the moment of completion prevents error." },
      1: { explain: "Six in the second (六二): The wife loses her carriage curtain — do not pursue. On the seventh day it returns. Small loss at completion — don't chase; it comes back." },
      2: { explain: "Nine in the third (九三): The High Ancestor attacked the demon territory — after three years he conquered it. Petty people should not be employed. Long, hard-fought completion." },
      3: { explain: "Six in the fourth (六四): Silk rags for patching — be alert all day. Vigilance in maintaining what has been completed." },
      4: { explain: "Nine in the fifth (九五): The neighbor in the east slaughters an ox — not equal to the neighbor in the west's simple offering. Sincere, modest continuation surpasses lavish but hollow maintenance." },
      5: { explain: "Six at the top (上六): Getting the head wet — danger. Immersed too deeply in completion, losing awareness of danger." }
    }
  },

  43: { /* 风火家人 KW#37, 巽上离下 */
    name: "Jiā Rén — The Family (Wind over Fire)",
    guaciExplain: "The family — the woman's perseverance is favorable. The family is the foundational unit of society. Each member in their proper role creates harmony that radiates outward.",
    xiangExplain: "Wind comes forth from fire — the family. The noble person's words have substance and their conduct is constant. Like wind spreading the warmth of fire, family influence radiates from the hearth.",
    modern: { career: "Work-life balance matters now. Career success at the expense of family ultimately fails. Build a career that supports your home, not one that destroys it.", wealth: "Family finances — budget together, plan together. Wealth that serves the family is wealth well-used. Financial harmony at home enables broader prosperity.", love: "The family hexagram — focus on building a stable, loving home. Each person in their proper place, each role honored. Home is where love is practiced daily.", health: "Family health — collective habits, shared meals, mutual care. A healthy family supports each member's wellbeing.", interpersonal: "Your family relationships are the template for all relationships. The warmth from the hearth radiates outward. Nurture your family first." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Establishing order in the family — regret disappears. Setting clear boundaries and roles from the start." },
      1: { explain: "Six in the second (六二): No agenda of her own — managing the household's food. Perseverance brings good fortune. Selfless care for the family's daily needs." },
      2: { explain: "Nine in the third (九三): The family chattering — regret but good fortune. The wife and children laughing — ultimately humiliation. Balance between familial warmth and needed discipline." },
      3: { explain: "Six in the fourth (六四): Enriching the family — great good fortune. The one who brings abundance to the household." },
      4: { explain: "Nine in the fifth (九五): The king approaches the family — do not worry. Good fortune. Leadership that honors and protects the family unit." },
      5: { explain: "Nine at the top (上九): With trust and dignity — ultimately good fortune. The family head whose integrity commands respect." }
    }
  },

  44: { /* 雷火丰 KW#55, 震上离下 */
    name: "Fēng — Abundance (Thunder over Fire)",
    guaciExplain: "Abundance — success. The king reaches the peak of abundance. Do not worry — be like the sun at midday. Abundance is fleeting — enjoy it while it lasts and share it freely.",
    xiangExplain: "Thunder and lightning together — abundance. The noble person decides litigations and applies punishments. Like the dramatic fullness of a thunderstorm, abundance brings the power to act decisively.",
    modern: { career: "You're at a peak — abundant opportunities, recognition, resources. Enjoy it! But know it's temporary. Use this peak to build for the valley beyond. Share the abundance.", wealth: "Financial peak — enjoy the abundance but resist the illusion of permanence. Save aggressively during plenty. Be the sun at midday: bright, generous, but aware of the coming afternoon.", love: "A peak of romantic abundance — deep connection, joy, shared richness. Cherish every moment. The sun at midday is beautiful because it doesn't last.", health: "Vitality at its peak. Channel abundant energy into sustainable practices. Don't burn through it — invest it.", interpersonal: "Social abundance — many friends, invitations, connections. Be generous with your social capital while you have it. The sun shares its light freely." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Meeting the sovereign — though it lasts only a week, no blame. Going brings praise. Brief but significant encounter at a peak moment." },
      1: { explain: "Six in the second (六二): Abundance of curtains — at midday seeing the Big Dipper. Going brings suspicion. With sincerity, good fortune. Abundance so great it obscures even the stars." },
      2: { explain: "Nine in the third (九三): Abundance of banners — at midday seeing the Small Star. Breaking the right arm — no blame. Abundance that brings impairment." },
      3: { explain: "Nine in the fourth (九四): Abundance of curtains — at midday seeing the Big Dipper. Meeting the hidden master — good fortune. Finding the wise person within overwhelming abundance." },
      4: { explain: "Six in the fifth (六五): Bringing brilliance — praise and good fortune. Celebrating the peak with radiance that attracts blessing." },
      5: { explain: "Six at the top (上六): Abundance of the house — screening off the home. Peering through the gate — still and silent, no one there. Three years without seeing anyone. Misfortune. The dark side of abundance: isolation within plenty." }
    }
  },

  45: { /* 离为火 KW#30, 离上离下 */
    name: "Lí — The Clinging (Fire)",
    guaciExplain: "The clinging — perseverance is favorable. Success. Raising a cow brings good fortune. Fire clings to fuel to shine — find what sustains your light and cling to it with devotion.",
    xiangExplain: "Brightness repeated — the clinging. The great person, with continuing brightness, illuminates the four directions. Like fire that must cling to what nourishes it, light depends on proper attachment.",
    modern: { career: "Find what fuels your professional fire and cling to it. Your brilliance depends on having the right fuel — meaningful work, supportive colleagues, growth opportunities.", wealth: "Wealth clings to value creation. Find what the world needs and cling to serving it. The cow (steady, productive investment) brings good fortune.", love: "Love is clinging in the best sense — mutual devotion that fuels each other's light. Find someone whose fire complements yours.", health: "Health clings to daily habits. Your vitality depends on what you cling to — nutritious food, regular movement, adequate rest.", interpersonal: "Cling to relationships that fuel your light. Some people are kindling, others are damp wood. Choose your attachments wisely." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Treading wrongly — but if respectful, no blame. Early misstep corrected through mindful awareness." },
      1: { explain: "Six in the second (六二): Yellow brightness — supreme good fortune. The centered, balanced radiance of mature fire." },
      2: { explain: "Nine in the third (九三): The setting sun's brightness — if not beating the earthen pot and singing, the old man sighs. Misfortune. Facing the end of radiance — either celebrate what was or lament." },
      3: { explain: "Nine in the fourth (九四): Sudden brightness — like fire, like death, like abandonment. The flare that burns out quickly." },
      4: { explain: "Six in the fifth (六五): Tears flowing like rivers — sighing and lamenting. Good fortune. Grief that releases and ultimately cleanses." },
      5: { explain: "Nine at the top (上九): The king goes on a punitive expedition — rejoicing in beheading the chief. Capturing followers — no blame. The brightness that purifies through decisive action." }
    }
  },

  46: { /* 泽火革 KW#49, 兑上离下 */
    name: "Gé — Revolution (Lake over Fire)",
    guaciExplain: "Revolution — on the appointed day, trust comes. Supreme success through perseverance. Regret disappears. When fire and water contend, transformation must come. Revolution timed rightly brings universal blessing.",
    xiangExplain: "Fire in the lake — revolution. The noble person orders the calendar and clarifies the seasons. Like water extinguishing fire or fire boiling water, fundamental change follows its proper timing.",
    modern: { career: "Radical career change is called for — not a tweak but a revolution. The timing must be right. When fire and water clash, fundamental transformation is the only way forward.", wealth: "Financial revolution — restructuring, career change, complete portfolio overhaul. On the right day, trust in the change comes. Time it carefully.", love: "Relationship needs fundamental change — not minor adjustments but revolution. The old pattern must die for new life to emerge. Time it with care.", health: "Health revolution — complete lifestyle overhaul. Not incremental changes but fundamental transformation. When the body demands revolution, listen.", interpersonal: "Social revolution — leave harmful communities, transform how you relate. The revolution must happen on the appointed day. Trust the timing." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Bound with yellow ox leather — firmly held. Preparation before revolution — the time has not yet come." },
      1: { explain: "Six in the second (六二): On the appointed day, make the revolution — going forward, good fortune, no blame. Revolution at exactly the right moment." },
      2: { explain: "Nine in the third (九三): Going forward, misfortune. Perseverance brings danger. The revolution is spoken of three times before there is trust. Revolution too hastily attempted." },
      3: { explain: "Nine in the fourth (九四): Regret disappears — with trust, changing the mandate. Good fortune. Revolution grounded in genuine trust and right purpose." },
      4: { explain: "Nine in the fifth (九五): The great person changes like a tiger — without divination, there is trust. The natural, authoritative revolution that everyone recognizes as right." },
      5: { explain: "Six at the top (上六): The noble person changes like a leopard — the petty person changes their face. Going forward, misfortune. Staying still, good fortune. Superficial vs. profound revolution." }
    }
  },

  47: { /* 天火同人 KW#13, 乾上离下 */
    name: "Tóng Rén — Fellowship (Heaven over Fire)",
    guaciExplain: "Fellowship in the open — success. Favorable to cross the great river. The noble person's perseverance brings advantage. Gathering with like-minded others in openness and sincerity creates power.",
    xiangExplain: "Heaven together with fire — fellowship. The noble person organizes things by kind and distinguishes them. Like flame rising to meet sky, kindred spirits find each other.",
    modern: { career: "Find your professional tribe. Open networking, transparent partnerships, genuine professional friendships create career momentum that isolated effort cannot match.", wealth: "Prosperity through shared ventures and open partnerships. Crowdfunding, cooperatives, collective investment models favored. Transparency builds trust.", love: "Seek a partner who is truly your equal in values and vision. The best relationships are fellowships — two kindred souls walking the same path.", health: "Shared health practices — group exercise, wellness communities — strengthen wellbeing. Kindred spirits make healthy habits sustainable.", interpersonal: "Build community in the light. Open, sincere friendships based on shared values create the strongest social fabric." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Fellowship at the gate — no blame. Open, public association from the very beginning." },
      1: { explain: "Six in the second (六二): Fellowship only within the clan — humiliation. Limiting associations to a narrow circle brings shame." },
      2: { explain: "Nine in the third (九三): Hiding arms in thickets — ascending the high mound. Three years without rising. Secretive, guarded behavior traps you in stagnation." },
      3: { explain: "Nine in the fourth (九四): Scaling the wall — unable to attack. Good fortune. Recognizing the limits of even allied power." },
      4: { explain: "Nine in the fifth (九五): Fellowship first weeps, then laughs — great armies meet after separation. Reconciliation after conflict brings deepest joy." },
      5: { explain: "Nine at the top (上九): Fellowship in the outskirts — no regret. Quiet solidarity on the margins has its own integrity." }
    }
  },

  /* ===== 兑宫 ===== */
  48: { /* 地泽临 KW#19, 坤上兑下 */
    name: "Lín — Approach (Earth over Lake)",
    guaciExplain: "Approach — supreme success with perseverance. But in the eighth month, misfortune comes. Good times approach — enjoy them while preparing for their natural conclusion.",
    xiangExplain: "The earth above the lake — the great approaches the small. The noble person's teaching and concern embrace all without limit. Like earth enfolding water, leadership approaches with nurturing care.",
    modern: { career: "A window of opportunity opens. Promotion, new projects, recognition approach. Be ready. But all peaks have descents — build durable foundations while ascending.", wealth: "Favorable financial period approaches. Maximize this window while maintaining discipline to save for less favorable cycles.", love: "Deepening intimacy approaches. Open your heart — but not naively. True intimacy is built on trust earned through consistent care.", health: "Health enters favorable phase. Recovery accelerates. Use this window to establish sustainable practices.", interpersonal: "New connections and deeper relationships approach. Welcome new people while nurturing existing bonds." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Approaching together — perseverance brings good fortune. United approach with those sharing your purpose." },
      1: { explain: "Nine in the second (九二): Approaching together — good fortune, nothing unfavorable. Harmony in approaching opportunities." },
      2: { explain: "Six in the third (六三): Sweet approach — nothing favorable. When concern subsides, no blame. Flattery ultimately fails; genuine concern endures." },
      3: { explain: "Six in the fourth (六四): Approaching directly — no blame. Honest, direct engagement is always appropriate." },
      4: { explain: "Six in the fifth (六五): Knowing how to approach — the great ruler's way. Good fortune. Wisdom in handling each situation and person." },
      5: { explain: "Six at the top (上六): Sincere approach — good fortune, no blame. The highest approach is grounded in genuine sincerity." }
    }
  },

  49: { /* 山泽损 KW#41, 艮上兑下 */
    name: "Sǔn — Decrease (Mountain over Lake)",
    guaciExplain: "Decrease — with sincerity, supreme good fortune. No blame. Perseverance is favorable. Going somewhere is favorable. What is decreased in one place increases another — accept necessary loss.",
    xiangExplain: "Mountain above the lake — decrease. The noble person controls anger and reduces desire. Like the lake's water rising to nourish the mountain, decrease in one realm becomes increase in another.",
    modern: { career: "Accept necessary decrease — letting go of a role, project, or ambition that no longer serves. What you lose in one area becomes gain in another. Control anger about losses.", wealth: "Financial decrease — accept it. Reduce spending, cut losses, simplify. The decrease that's accepted early is far less painful than the decrease that's resisted.", love: "Sometimes love requires decrease — giving up something for your partner. The sacrifice that's freely given strengthens the bond.", health: "Decrease what harms your health — sugar, stress, sedentary hours. Controlled decrease in harmful things is profound increase in wellbeing.", interpersonal: "Decrease anger and desire. These two consume more social capital than anything else. Controlled decrease in reactivity creates increase in respect." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Finishing affairs, quickly going — no blame. But carefully consider the decrease. Conclude and move on with measured reduction." },
      1: { explain: "Nine in the second (九二): Perseverance is favorable. Going forward, misfortune. Increasing without decreasing. Sometimes decrease is needed before increase can resume." },
      2: { explain: "Six in the third (六三): Three people traveling — decrease by one. One person traveling — finds a friend. Decrease that paradoxically creates connection." },
      3: { explain: "Six in the fourth (六四): Decreasing illness — quickly there is joy. No blame. Reducing what ails you brings swift relief." },
      4: { explain: "Six in the fifth (六五): Someone increases you with ten pairs of tortoise shells — none can refuse. Supreme good fortune. Even in decrease, unexpected blessings come." },
      5: { explain: "Nine at the top (上九): Increasing without decreasing — no blame. Perseverance brings good fortune. Going anywhere brings ministers without a household. The final stage where decrease has done its work." }
    }
  },

  50: { /* 水泽节 KW#60, 坎上兑下 */
    name: "Jié — Limitation (Water over Lake)",
    guaciExplain: "Limitation — success. Excessive limitation should not be persevered in. The lake holds only so much water — know your limits. Limitation that preserves is wise; limitation that constricts is harmful.",
    xiangExplain: "Water above the lake — limitation. The noble person creates measures and discusses virtuous conduct. Like a lake that can only hold so much, proper limits channel energy productively.",
    modern: { career: "Set clear limits — on working hours, on responsibilities you accept, on energy you give. The lake that overflows becomes a flood. Wise limitation creates sustainable career growth.", wealth: "Financial limitation — budgeting, spending caps, saving targets. Limitation that preserves is wise; limitation that prevents all enjoyment is harmful.", love: "Healthy boundaries in love. Limitation that protects each person's autonomy makes love sustainable. But excessive limitation becomes cold distance.", health: "Moderation in all things — the wisdom of limitation. Neither excess nor deprivation. The middle way of measured consumption.", interpersonal: "Set boundaries. The lake can only hold so much. Saying no to some social demands enables a full yes to what truly matters." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Not going out of the door and courtyard — no blame. Limitation that keeps you in safe, appropriate bounds." },
      1: { explain: "Nine in the second (九二): Not going out of the gate and courtyard — misfortune. Excessive limitation that prevents you from seizing opportunity." },
      2: { explain: "Six in the third (六三): Not knowing limitation — sighing and lamenting. No blame. The pain of failing to set limits." },
      3: { explain: "Six in the fourth (六四): Peaceful limitation — success. Limitation accepted with grace and inner calm." },
      4: { explain: "Nine in the fifth (九五): Sweet limitation — good fortune. Going brings praise. Limitation that feels satisfying and natural." },
      5: { explain: "Six at the top (上六): Bitter limitation — perseverance brings misfortune. Regret disappears. Excessive, harsh limitation that must be released." }
    }
  },

  51: { /* 风泽中孚 KW#61, 巽上兑下 */
    name: "Zhōng Fú — Inner Truth (Wind over Lake)",
    guaciExplain: "Inner truth — even pigs and fish are moved. Good fortune. Favorable to cross the great river. Perseverance is favorable. Sincerity so profound it reaches even the most unlikely beings.",
    xiangExplain: "Wind over the lake — inner truth. The noble person deliberates on litigation and delays execution. Like wind stirring the lake's surface, inner sincerity reaches and transforms all it touches.",
    modern: { career: "Your greatest career asset: authenticity. Inner truth that reaches and influences even unlikely allies. Be so genuine that even skeptics are moved.", wealth: "Financial integrity is magnetic. Inner truth in money matters attracts trust, partners, and opportunities that manipulation never could.", love: "Inner truth is the foundation of lasting love. Be so sincere that even the most guarded heart opens. Pigs and fish — the least responsive beings — are moved by genuine feeling.", health: "Listen to your body's inner truth. Beneath symptoms and surface complaints, your body speaks honestly. Hear it.", interpersonal: "Inner truth in relationships — no masks, no performance. This sincerity is so powerful it moves even those who usually resist connection." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Prepared — good fortune. If there is other involvement, not peaceful. Inner truth grounded in preparation." },
      1: { explain: "Nine in the second (九二): Calling crane in the shade — its young respond. I have a good cup; I will share it with you. Inner truth expressed in mutual sharing." },
      2: { explain: "Six in the third (六三): Finding a rival — now drumming, now ceasing; now weeping, now singing. Inconstancy born of comparing oneself to others." },
      3: { explain: "Six in the fourth (六四): The moon is nearly full — the horse's mate is lost. No blame. Maintaining truth even when facing loss." },
      4: { explain: "Nine in the fifth (九五): With inner truth, firmly bound — no blame. Truth that creates unshakeable bonds." },
      5: { explain: "Nine at the top (上九): The sound of the rooster rises to heaven — perseverance brings misfortune. Truth that proclaims itself too loudly loses its power." }
    }
  },

  52: { /* 雷泽归妹 KW#54, 震上兑下 */
    name: "Guī Mèi — The Marrying Maiden (Thunder over Lake)",
    guaciExplain: "The marrying maiden — going forward brings misfortune. Nothing favorable. A marriage or partnership where one party has less power — proceed with awareness of the imbalance.",
    xiangExplain: "Thunder above the lake — the marrying maiden. The noble person understands the impermanence of relationships and guards against what may go wrong. Like thunder stirring the lake, passion must be balanced with wisdom.",
    modern: { career: "You may be entering a position where you have less power — like a maiden marrying into a powerful family. Know the terms. The imbalance is real — navigate it consciously.", wealth: "Financial partnership with power imbalance. The junior partner must be especially careful. Understand what you're giving up for what you're gaining.", love: "A relationship with inherent power imbalance — age gap, status difference, emotional dependency. These can work but require extraordinary awareness and care.", health: "Health treatment with side effects — a 'marriage' to a therapy that both helps and harms. Weigh the costs carefully.", interpersonal: "Entering a social situation where you're the junior, outsider, or less powerful. Observe carefully before committing deeply." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): The marrying maiden as a secondary wife — the lame can walk. Going forward, good fortune. Accepting a secondary position with grace." },
      1: { explain: "Nine in the second (九二): The one-eyed can see — favorable for the recluse's perseverance. Limited but functional perspective in an imbalanced situation." },
      2: { explain: "Six in the third (六三): The marrying maiden waiting — returning as a secondary wife. Accepting diminished status as the price of the union." },
      3: { explain: "Nine in the fourth (九四): The marrying maiden delays — marriage comes late, in its own time. Patience before entering imbalanced partnership." },
      4: { explain: "Six in the fifth (六五): The emperor Yi gives his younger sister in marriage — the princess's sleeves were not as fine as the secondary wife's. The moon nearly full. Good fortune. Noble acceptance of modest position." },
      5: { explain: "Six at the top (上六): The woman carries a basket without fruit; the man stabs a sheep without blood. Nothing favorable. Ritual without substance — the empty form of union." }
    }
  },

  53: { /* 火泽睽 KW#38, 离上兑下 */
    name: "Kuí — Opposition (Fire over Lake)",
    guaciExplain: "Opposition — in small matters, good fortune. Fire rises, water descends — two forces moving apart. In fundamental opposition, find unity in small things.",
    xiangExplain: "Fire above, lake below — opposition. The noble person, amid differences, seeks common ground. Like fire and water that can never mix yet both serve life, opposites can coexist in larger harmony.",
    modern: { career: "Fundamental disagreement at work — different values, visions, or approaches. Don't try to make fire and water mix. Find small areas of practical cooperation despite the big differences.", wealth: "Financial approach fundamentally at odds with partners or market. Accept the opposition — find small common ground while protecting your position.", love: "Fundamental differences with your partner — values, goals, personality. These don't have to end the relationship. Fire and water both serve life. Find the small harmonies.", health: "Opposing health advice or conflicting symptoms. Accept the complexity rather than forcing a single explanation. Small, practical steps matter more than grand unified theories.", interpersonal: "You're in fundamental opposition with someone. Stop trying to convert them. Accept the difference and find small patches of common ground. Peaceful coexistence is possible." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Regret disappears. Losing the horse — do not pursue; it returns. Seeing an evil person — no blame. Let go of what opposes you; focus on what returns." },
      1: { explain: "Nine in the second (九二): Meeting the master in an alley — no blame. Finding connection in unexpected, informal places." },
      2: { explain: "Six in the third (六三): The carriage dragged back, the ox halted — the person's hair and nose cut off. No good beginning but a good end. Painful opposition that eventually resolves." },
      3: { explain: "Nine in the fourth (九四): Opposition and isolation — meeting a true man. Connecting with one genuine person amid widespread alienation." },
      4: { explain: "Six in the fifth (六五): Regret disappears. The companion bites through the skin — going forward, what blame? Trusted ally breaks through opposition." },
      5: { explain: "Nine at the top (上九): Opposition and isolation — seeing a pig covered in mud, a cartload of demons. First drawing the bow, then laying it aside. Not a robber — a suitor. Going brings joy. Mistaking friend for foe in opposition; seeing clearly brings reconciliation." }
    }
  },

  54: { /* 兑为泽 KW#58, 兑上兑下 */
    name: "Duì — The Joyous (Lake)",
    guaciExplain: "The joyous — success. Perseverance is favorable. The open lake that reflects all and shares freely — joy that comes from genuine exchange.",
    xiangExplain: "Lakes joined together — the joyous. The noble person, with friends, discusses and practices. Like two lakes sharing water, joy multiplies through genuine exchange with others.",
    modern: { career: "Joy through genuine exchange with colleagues. Not networking as transaction, but real sharing of ideas and support. The joyous workplace is built on mutual encouragement.", wealth: "Joy in sharing abundance. The lake that gives water to others is continuously replenished. Generous wealth multiplies.", love: "Joy as the foundation of love. Not duty or passion alone, but genuine delight in each other's company. Joy shared is joy doubled.", health: "Joy as medicine. The joyous heart heals the body. Seek activities, people, and environments that spark genuine delight.", interpersonal: "Be a lake of joy — reflect beauty, share freely, welcome all. Your genuine delight in others becomes their delight in you." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Harmonious joy — good fortune. Joy that brings people together rather than dividing them." },
      1: { explain: "Nine in the second (九二): Sincere joy — good fortune. Regret disappears. Joy grounded in authenticity rather than performance." },
      2: { explain: "Six in the third (六三): Coming joy — misfortune. Joy that seeks you for the wrong reasons; be discerning about what delights you." },
      3: { explain: "Nine in the fourth (九四): Deliberating about joy — not yet at peace. Refusing harmful joy brings healing. Discernment about what truly brings happiness." },
      4: { explain: "Nine in the fifth (九五): Trusting in what decays — danger. Placing joy in what is crumbling." },
      5: { explain: "Six at the top (上六): Leading in joy — the joy of misleading others. Discernment of genuine vs. false sources of happiness." }
    }
  },

  55: { /* 天泽履 KW#10, 乾上兑下 */
    name: "Lǚ — Treading Carefully (Heaven over Lake)",
    guaciExplain: "Treading on the tiger's tail — it does not bite. Success. Proceeding with careful propriety through dangerous circumstances brings surprising safety.",
    xiangExplain: "Heaven above, lake below — treading. The noble person distinguishes above from below and settles the people's intentions. Understanding proper roles and boundaries prevents conflict.",
    modern: { career: "Navigating a politically sensitive environment. Respect hierarchy, observe proper conduct. Like walking past a sleeping tiger, quiet competence keeps you safe where boldness would provoke attack.", wealth: "Financial dealings carry hidden risks. Due diligence, proper documentation, established procedures protect you. Not the time for regulatory gray areas.", love: "Power dynamics need careful navigation. Mutual respect for each other's dignity keeps the connection healthy.", health: "Physical condition vulnerable — one wrong move triggers problems. Adhere carefully to medical advice; don't push limits.", interpersonal: "Social situations require diplomatic awareness. Understand unwritten rules and power dynamics before speaking. Tact is your shield." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Simple conduct — going forward, no blame. Unpretentious, straightforward behavior in new circumstances." },
      1: { explain: "Nine in the second (九二): Treading smoothly and calmly — the recluse's perseverance brings good fortune. Quiet, steady path without seeking attention." },
      2: { explain: "Six in the third (六三): The one-eyed can see; the lame can walk. But treading the tiger's tail brings biting — misfortune. Overestimating abilities in dangerous territory." },
      3: { explain: "Nine in the fourth (九四): Treading the tiger's tail — with extreme caution, ultimately good fortune. Recognizing danger and acting with utmost care." },
      4: { explain: "Nine in the fifth (九五): Resolute treading — perseverance with awareness of danger. Decisive yet cautious action when necessary." },
      5: { explain: "Nine at the top (上九): Examine your conduct, consider the omens — when complete, supreme good fortune. Reflecting on your path and its signs brings highest blessing." }
    }
  },

  /* ===== 乾宫 ===== */
  56: { /* 地天泰 KW#11, 坤上乾下 */
    name: "Tài — Peace (Earth over Heaven)",
    guaciExplain: "Peace — the small departs, the great arrives. Good fortune, success. Heaven and earth in harmonious communication — a time of peace, prosperity, and smooth progress.",
    xiangExplain: "Heaven and earth in communication — peace. The sovereign shapes and completes the way of heaven and earth, guiding the people to harmony. This is the ideal state of balance between yang and yin.",
    modern: { career: "Golden period where everything aligns. Promotions, opportunities, recognition come naturally. This harmony is precious because it's temporary. Build lasting foundations while the winds favor you.", wealth: "Financial flows smooth and favorable. Strategic growth time — invest in solid foundations. Diversify and prepare for less favorable times.", love: "Perfect harmony. Communication flows freely; understanding is deep. Cherish this — the most beautiful gardens still need tending.", health: "Vitality at peak. Establish exercise and nutrition habits that will sustain you when energy fluctuates.", interpersonal: "Relationships harmonious and supportive. Bridge-building comes naturally. Use this period to strengthen social foundation." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Pulling out a reed brings others — going forward, good fortune. Like connected roots, one good action triggers positive development." },
      1: { explain: "Nine in the second (九二): Embracing the wilds, crossing rivers, not abandoning the distant — the mean is not lost. Inclusiveness during good times prevents future isolation." },
      2: { explain: "Nine in the third (九三): No plain without a slope; no going without returning. In hardship, persevere without blame. Peace alternates with difficulty — accept natural cycles." },
      3: { explain: "Six in the fourth (六四): Fluttering down — not relying on wealth. With neighbors, sincere and without戒备. Genuine humility and community create true security." },
      4: { explain: "Six in the fifth (六五): The emperor Yi gives his younger sister in marriage — supreme good fortune. Auspicious unions bring the greatest fortune." },
      5: { explain: "Six at the top (上六): The city wall falls into the moat. Do not use the army. Proclaim orders only within your city. When peace crumbles, aggression worsens the collapse." }
    }
  },

  57: { /* 山天大畜 KW#26, 艮上乾下 */
    name: "Dà Chù — Great Accumulation (Mountain over Heaven)",
    guaciExplain: "Great accumulation — perseverance is favorable. Not eating at home brings good fortune. Favorable to cross the great river. Storing great virtue and knowledge — the mountain holds heaven's energy within.",
    xiangExplain: "Heaven within the mountain — great accumulation. The noble person studies the words and deeds of the past to accumulate virtue. Like a mountain containing heaven's vast energy, true wealth is stored wisdom.",
    modern: { career: "Accumulate skills, knowledge, and relationships patiently. Great careers are built on great accumulation — years of learning stored like a mountain containing heaven.", wealth: "Great accumulation of wealth through patient, disciplined saving and investing. Not flashy gains but massive stores built over time.", love: "Love deepened through shared history and accumulated trust. The mountain of shared memories contains heaven's worth of meaning.", health: "Great accumulation of vitality through years of disciplined health practices. The stored health reserves carry you through crisis.", interpersonal: "Accumulate wisdom from every relationship. Study the words and deeds of those who came before. The mountain of social wisdom protects and guides." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): There is danger — it is favorable to stop. Knowing when not to advance in accumulation." },
      1: { explain: "Nine in the second (九二): The cart's axle straps come off. Inability to move despite great stores." },
      2: { explain: "Nine in the third (九三): A fine horse pursues — perseverance through difficulty is favorable. Practicing chariot driving and defense daily — it is favorable to go somewhere. Prepared accumulation enables action." },
      3: { explain: "Six in the fourth (六四): The young bull's horn board — supreme good fortune. Preventive measures early in accumulation prevent future danger." },
      4: { explain: "Six in the fifth (六五): The tusked boar's tusks — good fortune. Controlled power within great accumulation." },
      5: { explain: "Nine at the top (上九): Reaching the way of heaven — success. The ultimate accumulation that opens to universal understanding." }
    }
  },

  58: { /* 水天需 KW#5, 乾上坎下 */
    name: "Xū — Waiting (Water over Heaven)",
    guaciExplain: "Waiting — with sincerity, light shines. Perseverance brings good fortune. Favorable to cross the great river. Patient waiting with inner trust — clouds gather before the nourishing rain.",
    xiangExplain: "Clouds rise to heaven — waiting. The noble person enjoys food and drink, resting in peace. Like clouds gathering before rain, nourishment and rest prepare one for the right moment.",
    modern: { career: "You're in a holding pattern. Don't waste the wait in frustration — use it for skill-building and preparation. When the door opens, you'll be ready.", wealth: "Financial growth requires patience. Like clouds gathering before rain, investments need time. Avoid impulsive moves — the waiting is part of the growth.", love: "Let the relationship develop naturally. Pushing for commitment before both are ready creates tension. Enjoy getting to know each other.", health: "Recovery takes time. Your body knows its timeline. Provide good nutrition, rest, and gentle care rather than demanding quick results.", interpersonal: "Not every relationship needs immediate depth. Some connections need time to ripen. Be present without being demanding." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Waiting in the open countryside — favorable to persist. No blame. Patience in distant, uncertain circumstances." },
      1: { explain: "Nine in the second (九二): Waiting on the sand — some gossip, but ultimately good fortune. Even uncomfortable waiting brings favorable outcome." },
      2: { explain: "Nine in the third (九三): Waiting in the mud — invites the robber. Lingering too long in a compromised position attracts trouble." },
      3: { explain: "Six in the fourth (六四): Waiting in blood — emerge from the cave. When trapped in danger, the only way out is through." },
      4: { explain: "Nine in the fifth (九五): Waiting with wine and food — perseverance brings good fortune. Confident patience, enjoying life while waiting." },
      5: { explain: "Six at the top (上六): Entering the cave — three uninvited guests arrive. Treat them with respect — ultimately good fortune. Unexpected visitors handled gracefully bring blessing." }
    }
  },

  59: { /* 风天小畜 KW#9, 巽上乾下 */
    name: "Xiǎo Chù — Small Accumulation (Wind over Heaven)",
    guaciExplain: "Small accumulation — success. Dense clouds but no rain from our western suburbs. The time of full release has not arrived. Patient, incremental progress toward your goal.",
    xiangExplain: "Wind blows across heaven — small accumulation. The noble person cultivates refinement in cultured arts and virtue. Like wind shaping clouds that don't yet rain, gentle cultivation precedes breakthrough.",
    modern: { career: "Phase of incremental progress — don't despise small steps. Like an artist refining technique, focus on mastery rather than meteoric success. Skills compound into breakthroughs.", wealth: "Steady, modest accumulation. Regular saving, incremental growth, patient wealth-building. The clouds gather — rain will come.", love: "Relationship grows through small, consistent acts of love rather than grand gestures. Appreciate quiet intimacy of daily care.", health: "Small, consistent habits matter more than dramatic interventions. Daily exercise, mindful eating, adequate rest accumulate into wellbeing.", interpersonal: "Cultivate refinement in interactions. Genuine courtesy, thoughtful communication, small kindnesses build a reputation that opens doors." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Return to the path — how could there be blame? Good fortune. Returning to what is right brings blessing." },
      1: { explain: "Nine in the second (九二): Drawn along to return — good fortune. Being pulled back to the right path is still a blessing." },
      2: { explain: "Nine in the third (九三): The cart's spokes give way — husband and wife glare. When supporting structure fails, relationships strain." },
      3: { explain: "Six in the fourth (六四): With sincerity, bloodshed avoided and fear departs. No blame. Genuine good faith resolves conflicts before violence." },
      4: { explain: "Nine in the fifth (九五): With sincerity, embracing richness through neighbors. Wealth shared in trust and community multiplies." },
      5: { explain: "Nine at the top (上九): The rain has come; rest achieved. But the moon nearly full — going forth meets misfortune. Know when achievement is sufficient." }
    }
  },

  60: { /* 雷天大壮 KW#34, 震上乾下 */
    name: "Dà Zhuàng — Great Power (Thunder over Heaven)",
    guaciExplain: "Great power — perseverance is favorable. Thunder rolls across heaven — powerful yang energy. Great power must be guided by righteousness, or it becomes destruction.",
    xiangExplain: "Thunder above heaven — great power. The noble person does not tread paths that are not proper. Like thunder that can terrify or illuminate, great power is dangerous without righteousness.",
    modern: { career: "You have significant power and momentum. The critical question: is it guided by integrity? Great power without righteousness is destruction waiting to happen.", wealth: "Financial power is strong. But power without principle creates eventual disaster. Use financial strength ethically.", love: "Strong passion and attraction — great romantic power. But power must respect boundaries. Love's strength is tested by its gentleness.", health: "Great physical vitality. Channel this power wisely — it can build or burn. Don't overdo it just because you can.", interpersonal: "You hold significant social power right now. Use it to lift others, not dominate. The noble person doesn't tread improper paths." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Power in the toes — going forward, misfortune. With sincerity. Power applied too early, too low, before it's ready." },
      1: { explain: "Nine in the second (九二): Perseverance brings good fortune. Power held in check, guided by principle." },
      2: { explain: "Nine in the third (九三): The petty person uses power; the noble person does not. Perseverance brings danger. A ram butting a hedge — horns entangled. Power misused traps itself." },
      3: { explain: "Nine in the fourth (九四): Perseverance brings good fortune. Regret disappears. The hedge opens — no entanglement. Power finding its proper channel." },
      4: { explain: "Six in the fifth (六五): Losing the ram easily — no regret. Letting go of aggressive power with ease." },
      5: { explain: "Six at the top (上六): The ram butts the hedge — cannot retreat, cannot advance. Nothing favorable. Difficulty, but good fortune. Power at its limit, learning through difficulty." }
    }
  },

  61: { /* 火天大有 KW#14, 离上乾下 */
    name: "Dà Yǒu — Great Possession (Fire over Heaven)",
    guaciExplain: "Great possession — supreme success. Fire blazes above heaven illuminating all. Abundance flows to those whose virtue can contain it. Great possession requires great responsibility.",
    xiangExplain: "Fire blazes above heaven — great possession. The noble person suppresses evil and promotes good, obeying heaven's auspicious mandate. Great possession must serve the greater good.",
    modern: { career: "You're at a peak of achievement and influence. Resources, recognition, opportunities abundant. The test: how will you use your platform? Generosity sustains success; arrogance destroys it.", wealth: "Financial abundance flows. This is harvest time. Share generously, invest wisely, build reserves. True prosperity is measured by what you give.", love: "Relationship rich with affection, resources, mutual care. Cherish through daily gratitude and generosity. Love multiplies when shared.", health: "Vitality abundant. Channel peak wellness into sustainable habits. The exercise and nutrition patterns you establish now sustain future you.", interpersonal: "Social capital high — connections, goodwill, influence. Use your social wealth to lift others. The most respected people use abundance to benefit all." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): No association with what is harmful — not blameworthy. If mindful of difficulty, no blame. Avoiding harmful entanglements from the start." },
      1: { explain: "Nine in the second (九二): A great wagon to carry — going anywhere, no blame. Substantial resources, properly managed." },
      2: { explain: "Nine in the third (九三): A prince offers to the Son of Heaven — petty people cannot do this. Great possession dedicated to higher purposes." },
      3: { explain: "Nine in the fourth (九四): Not boasting of abundance — no blame. True wealth requires no display." },
      4: { explain: "Six in the fifth (六五): Trust that is dignified — good fortune. Confidence coupled with sincerity commands respect." },
      5: { explain: "Nine at the top (上九): From heaven comes blessing — good fortune, nothing unfavorable. When great possession is wielded with virtue, heaven protects." }
    }
  },

  62: { /* 泽天夬 KW#43, 兑上乾下 */
    name: "Guài — Breakthrough (Lake over Heaven)",
    guaciExplain: "Breakthrough — proclaimed in the king's court. Sincere declaration with danger. Announce to your own city. Not favorable to take up arms. Favorable to go somewhere. Decisive resolution — better through truth than force.",
    xiangExplain: "Lake rises to heaven — breakthrough. The noble person shares wealth with those below. Staying where one's virtue is, one invites dislike. Like water rising to heaven's height, decisive action resolves long-standing tension.",
    modern: { career: "A long-building situation needs decisive resolution. The breakthrough must be proclaimed openly — secret maneuvers backfire. Truth, not force, wins the day.", wealth: "Financial breakthrough — a long-stuck situation resolves. Share the gains with those who supported you. Hoarding the breakthrough invites resentment.", love: "A long-building tension in relationship needs decisive resolution. Proclaim your truth openly; hidden resentments poison. Favorable to act, not to fight.", health: "Health breakthrough — a long-standing condition finally resolves or is understood. Share what you've learned with others.", interpersonal: "A social breakthrough — long-standing tension or conflict resolves. Proclaim the resolution openly. Those who hoard social breakthroughs invite resentment." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九): Power in the forward toes — going brings defeat. Blame. First impulse toward breakthrough — premature action fails." },
      1: { explain: "Nine in the second (九二): Crying out at dusk — weapons at night. Do not worry. Prepared vigilance amid breakthrough tension." },
      2: { explain: "Nine in the third (九三): Power in the cheekbones — misfortune. The noble person resolves alone — encountering rain, getting wet, displeased but no blame. Breakthrough that isolates." },
      3: { explain: "Nine in the fourth (九四): Buttocks without skin — walking haltingly. Led like a sheep — regret disappears. Not listening to words. Following others through the breakthrough." },
      4: { explain: "Nine in the fifth (九五): The weed-free hill — the noble person resolves resolutely. Walking the middle path, no blame. Clean, decisive breakthrough from centered position." },
      5: { explain: "Six at the top (上六): No cry — ultimately misfortune. Failure to proclaim the breakthrough when it's needed." }
    }
  },

  63: { /* 乾为天 KW#1, 乾上乾下 */
    name: "Qián — The Creative (Heaven)",
    guaciExplain: "The Qian hexagram: supreme success through perseverance. [元亨利贞 Yuán Hēng Lì Zhēn — Origination (元): the primal creative force; Prosperity (亨): flourishing through harmony; Benefit (利): nourishing what is right; Steadfastness (貞): persevering in the correct path — the four cardinal virtues of Heaven.]",
    xiangExplain: "Heaven's movement is vigorous and ceaseless. The noble person, observing this, strengthens themselves without rest. [天行健 (Tiān Xíng Jiàn), 君子以自强不息 (Jūn Zǐ Yǐ Zì Qiáng Bù Xī): Heaven moves with powerful constancy — the noble person ceaselessly cultivates self-renewal.]",
    modern: { career: "You're at a creative peak — initiate boldly and persist wisely. Like the dragon's six stages, know when to hide, when to emerge, when to soar, and when to retreat. Supreme success comes through aligning personal ambition with universal principles.", wealth: "Financial creativity at its peak. The four virtues apply: originate new ventures (元), develop them prosperously (亨), ensure mutual benefit (利), and maintain through persistence (貞).", love: "Yang energy at its fullest — confident, creative, initiating. But the dragon that soars too high regrets. Balance creative power with receptive wisdom.", health: "Peak vitality and creative energy. The six dragon stages map to life phases — honor where you are in the cycle. Ceaseless self-renewal is the heaven-like path to health.", interpersonal: "Lead with creative integrity. The noble person strengthens themselves ceaselessly — your example inspires more than any words. But the arrogant dragon (亢龙) alienates; true leadership combines power with humility." },
    yaoci: {
      0: { explain: "Nine at the beginning (初九, Chū Jiǔ): Hidden Dragon, Do Not Act [潜龙勿用 Qián Lóng Wù Yòng]. When the dragon lies hidden in the depths, one should bide time and not yet take action. A metaphor for unrecognized talent: wait patiently, prepare diligently." },
      1: { explain: "Nine in the second (九二, Jiǔ Èr): Dragon Appearing in the Field [见龙在田 Xiàn Lóng Zài Tián]. The dragon emerges and is seen in the open field. It is favorable to see the great person. Your talents begin to be recognized — seek worthy mentors and collaborators." },
      2: { explain: "Nine in the third (九三, Jiǔ Sān): The noble person is vigorous all day; at night, still vigilant. Danger, but no blame [终日乾乾 Zhōng Rì Qián Qián]. Ceaseless effort by day, self-reflection by night. The path of constant self-cultivation." },
      3: { explain: "Nine in the fourth (九四, Jiǔ Sì): Leaping at the abyss — no blame [或跃在渊 Huò Yuè Zài Yuān]. The dragon tests its wings at the edge of the deep. A critical transition point — leap forward or retreat; either can be correct." },
      4: { explain: "Nine in the fifth (九五, Jiǔ Wǔ): Flying Dragon in the Heavens [飞龙在天 Fēi Lóng Zài Tiān]. It is favorable to see the great person. The dragon soars at its zenith — at the peak of power, influence, and creative achievement. The most auspicious line in the I Ching." },
      5: { explain: "Nine at the top (上九, Shàng Jiǔ): Arrogant Dragon Will Have Regret [亢龙有悔 Kàng Lóng Yǒu Huǐ]. The dragon that flies too high, beyond its proper place, falls into isolation and regret. Power pushed beyond its natural limit brings downfall. Know when to descend." }
    }
  }
};

